// ─── Persistent storage (logins, accounts, settings survive reloads) ───────────
// Persists most of _db to localStorage so logged-in users, registered accounts,
// reminders, audit history, etc. survive a page refresh / app restart on this
// device. Cached inventory (_db.cache) is intentionally excluded — it's
// re-fetched from MarketCheck/demo data on load and can get large.
var DB_STORAGE_KEY = "videovault_db_v2";
function loadDB(){
  try{
    if(typeof localStorage==="undefined")return;
    try{ localStorage.removeItem("videovault_db_v1"); }catch(e){}
    var raw=localStorage.getItem(DB_STORAGE_KEY);
    if(!raw)return;
    var saved=JSON.parse(raw);
    Object.keys(saved).forEach(function(k){
      if(k==="cache")return;
      _db[k]=saved[k];
    });
  }catch(e){ /* corrupt or unavailable storage — start fresh */ }
}
function persistDB(){
  try{
    if(typeof localStorage==="undefined")return;
    var snapshot=Object.assign({},_db,{cache:{}});
    localStorage.setItem(DB_STORAGE_KEY,JSON.stringify(snapshot));
  }catch(e){ /* storage full or unavailable — fail silently */ }
}
loadDB();
var MAX_LOGIN_ATTEMPTS = 5;
var LOCKOUT_MS = 15 * 60 * 1000; // 15 minutes
function checkLoginRate(email) {
  var rec = _db.loginAttempts[email];
  if (!rec) return {allowed:true, remaining:MAX_LOGIN_ATTEMPTS};
  if (rec.lockedUntil && Date.now() < rec.lockedUntil) {
    var mins = Math.ceil((rec.lockedUntil - Date.now()) / 60000);
    return {allowed:false, remaining:0, mins:mins};
  }
  if (rec.lockedUntil && Date.now() >= rec.lockedUntil) {
    delete _db.loginAttempts[email]; return {allowed:true, remaining:MAX_LOGIN_ATTEMPTS};
  }
  var remaining = MAX_LOGIN_ATTEMPTS - (rec.count||0);
  return {allowed:remaining>0, remaining:remaining};
}
function recordLoginFail(email) {
  if (!_db.loginAttempts[email]) _db.loginAttempts[email] = {count:0};
  _db.loginAttempts[email].count++;
  if (_db.loginAttempts[email].count >= MAX_LOGIN_ATTEMPTS) {
    _db.loginAttempts[email].lockedUntil = Date.now() + LOCKOUT_MS;
  }
}
function clearLoginAttempts(email) { delete _db.loginAttempts[email]; }

// ── Face ID / Touch ID (WebAuthn) ────────────────────────────────────────────
function faceIdAvailable(){
  return !!(window.PublicKeyCredential && navigator.credentials);
}
function getFaceIdEmail(){
  return _db.faceIdEmail || null;
}
async function registerFaceId(email, name){
  if(!faceIdAvailable())return {ok:false,err:"Face ID / Touch ID is not available on this device."};
  try{
    var challenge=new Uint8Array(32);
    window.crypto.getRandomValues(challenge);
    var userId=new Uint8Array(16);
    window.crypto.getRandomValues(userId);
    var cred=await navigator.credentials.create({
      publicKey:{
        challenge:challenge,
        rp:{name:"Video Vault"},
        user:{id:userId,name:email,displayName:name||email},
        pubKeyCredParams:[{alg:-7,type:"public-key"},{alg:-257,type:"public-key"}],
        authenticatorSelection:{authenticatorAttachment:"platform",userVerification:"required"},
        timeout:60000,
        attestation:"none",
      }
    });
    if(!cred)return {ok:false,err:"Setup was cancelled."};
    if(!_db.faceIdCreds)_db.faceIdCreds={};
    _db.faceIdCreds[email.toLowerCase()]={credId:cred.id};
    _db.faceIdEmail=email.toLowerCase();
    persistDB();
    return {ok:true};
  }catch(e){
    return {ok:false,err:"Could not set up Face ID: "+(e.message||"unknown error")};
  }
}
async function verifyFaceId(email){
  if(!faceIdAvailable())return {ok:false,err:"Face ID / Touch ID is not available on this device."};
  var rec=_db.faceIdCreds&&_db.faceIdCreds[email.toLowerCase()];
  if(!rec)return {ok:false,err:"Face ID is not set up for this account."};
  try{
    var challenge=new Uint8Array(32);
    window.crypto.getRandomValues(challenge);
    var assertion=await navigator.credentials.get({
      publicKey:{
        challenge:challenge,
        allowCredentials:[{id:Uint8Array.from(atob(rec.credId.replace(/-/g,"+").replace(/_/g,"/")),function(c){return c.charCodeAt(0);}),type:"public-key"}],
        userVerification:"required",
        timeout:60000,
      }
    });
    if(!assertion)return {ok:false,err:"Face ID was cancelled."};
    return {ok:true};
  }catch(e){
    return {ok:false,err:"Face ID verification failed. Use your password instead."};
  }
}
function clearFaceId(email){
  if(_db.faceIdCreds)delete _db.faceIdCreds[email.toLowerCase()];
  if(_db.faceIdEmail===email.toLowerCase())_db.faceIdEmail=null;
}

