// Known-good corporate domains — always allowed regardless of the blocklist below.
var ALLOWED_DOMAINS = [
  "sonicautomotive.com",
  "allprorecon.com",
  "allproreconditioning.com",
];
// Individual Sonic dealerships often use their own domain (e.g.
// "@masseycadillac.com") rather than sonicautomotive.com, so we can't
// maintain a full allowlist of every dealer's domain. Instead we block
// well-known free/personal email providers and allow everything else —
// any other domain is assumed to be a dealer's business domain.
var BLOCKED_DOMAINS = [
  "gmail.com","googlemail.com",
  "yahoo.com","yahoo.co.uk","ymail.com","rocketmail.com",
  "hotmail.com","outlook.com","live.com","msn.com",
  "icloud.com","me.com","mac.com",
  "aol.com",
  "protonmail.com","proton.me","pm.me",
  "gmx.com","gmx.us",
  "mail.com","zoho.com","yandex.com",
];
function isAllowedEmail(email){
  var e=(email||"").toLowerCase().trim();
  if(e===MASTER_ADMIN_EMAIL)return true; // Master Admin bypasses all checks
  var parts=e.split("@");
  if(parts.length!==2)return false;
  var domain=parts[1].trim();
  if(ALLOWED_DOMAINS.indexOf(domain)!==-1)return true;
  if(BLOCKED_DOMAINS.indexOf(domain)!==-1)return false;
  return true; // assume any other domain is a dealership's business domain
}

function getUsers()         { return _db.users; }
