// ─── Formatters ────────────────────────────────────────────────────────────────
function fmtPrice(n) { return "$" + Number(n||0).toLocaleString(); }
function fmtMiles(n) { return Number(n||0).toLocaleString() + " mi"; }
function fmtTime(s)  { return String(Math.floor(s/60)).padStart(2,"0") + ":" + String(s%60).padStart(2,"0"); }
function fmtSize(b)  { return b > 1e6 ? (b/1e6).toFixed(1) + " MB" : Math.round(b/1e3) + " KB"; }
function fmtDate(d)  { return new Date(d).toLocaleDateString(undefined,{month:"short",day:"numeric",year:"numeric"}); }
function fmtDaysAgo(d) {
  var diff = Math.floor((Date.now()-new Date(d))/86400000);
  if(diff===0) return "Today";
  if(diff===1) return "Yesterday";
  return diff + " days ago";
}
function randCode() { return String(Math.floor(100000+Math.random()*900000)); }
// Sends a verification code via the Resend email worker. Returns {ok:true} on
// success, {ok:false} on any failure (network error, worker not deployed,
// missing API key, etc.) — callers should fall back to showing the code
// on-screen in that case so testing/dev is never blocked.
async function sendVerificationEmail(email, code, name){
  try{
    var res=await fetch(EMAIL_WORKER_URL, {
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({to:email, code:code, name:name||""})
    });
    if(!res.ok)return {ok:false};
    var data=await res.json().catch(function(){return {};});
    return {ok:data.ok!==false};
  }catch(e){
    return {ok:false};
  }
}
function randId()   { return Date.now().toString(36) + Math.random().toString(36).slice(2,6); }

