function VideoThumb(p) {
  var ref=useRef(null); var [ready,setReady]=useState(false);
  var isPhoto=p.isPhoto||(p.blob&&p.blob.type&&p.blob.type.indexOf("image")===0);
  var [imgUrl,setImgUrl]=useState(null);
  useEffect(function(){
    if(!p.blob)return;
    if(isPhoto){
      var iu=URL.createObjectURL(p.blob);
      setImgUrl(iu); setReady(true);
      return function(){URL.revokeObjectURL(iu);};
    }
    if(!ref.current)return;
    var url=URL.createObjectURL(p.blob);
    var v=document.createElement("video");
    v.src=url; v.muted=true; v.currentTime=1; v.preload="metadata";
    v.onloadeddata=function(){
      var c=ref.current; if(!c)return;
      c.width=v.videoWidth||320; c.height=v.videoHeight||240;
      c.getContext("2d").drawImage(v,0,0);
      setReady(true); URL.revokeObjectURL(url);
    };
    v.onerror=function(){URL.revokeObjectURL(url);};
  },[p.blob]);
  if(isPhoto){
    return <div style={{position:"absolute",inset:0}}>
      {!ready&&<div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,color:"#2a2d35",background:"#141720"}}>📷</div>}
      {imgUrl&&<img src={imgUrl} style={{display:ready?"block":"none",position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover"}}/>}
    </div>;
  }
  return <div>
    {!ready&&<div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,color:"#2a2d35",background:"#141720"}}>🎬</div>}
    <canvas ref={ref} style={{display:ready?"block":"none",position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover"}}/>
  </div>;
}
