function DealerPicker(p) {
  var th=p.th;
  var [q,setQ]=useState("");
  var dealers=SONIC_DEALERS.filter(function(d){
    if(!q)return true;
    return d.name.toLowerCase().includes(q.toLowerCase())||d.city.toLowerCase().includes(q.toLowerCase());
  });
  var sel=SONIC_DEALERS.find(function(d){return d.id===p.dealerId;});
  if(sel) return <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",background:"#00d97e0d",border:"1px solid #00d97e33",borderRadius:10,padding:"12px 14px",marginBottom:6}}>
    <div><div style={{fontSize:14,color:"#00d97e",fontWeight:700}}>✓ {sel.name}</div><div style={{fontSize:11,color:th.muted}}>{sel.city}</div></div>
    <button onClick={function(){p.setDealerId("");}} style={{background:"transparent",border:"none",color:th.muted,cursor:"pointer",fontSize:12,fontFamily:"'Barlow',sans-serif"}}>Change</button>
  </div>;
  return <div>
    <input style={{...inp(th),marginBottom:6}} placeholder="Search by name or city..." value={q} onChange={function(e){setQ(e.target.value);}}/>
    <div style={{maxHeight:190,overflowY:"auto",background:th.inp,border:"1px solid "+th.inpBorder,borderRadius:10,marginBottom:4}}>
      {dealers.map(function(d){
        return <div key={d.id} onClick={function(){p.setDealerId(d.id);setQ("");}} style={{padding:"11px 14px",cursor:"pointer",borderBottom:"1px solid "+th.border}}>
          <div style={{fontSize:14,color:th.text,fontWeight:600}}>{d.name}</div>
          <div style={{fontSize:11,color:th.muted}}>{d.city}</div>
        </div>;
      })}
      {dealers.length===0&&<div style={{padding:14,fontSize:13,color:th.muted}}>No results</div>}
    </div>
  </div>;
}
function PasskeyModal(p) {
  var th=p.th;
  var [pk,setPk]=useState("");
  var [err,setErr]=useState("");
  var MANAGER_PK=getStoreSettings(p.dealerId||"").managerPk||"1234";
  function tryUnlock(){
    if(pk===MANAGER_PK){p.onUnlock();setErr("");setPk("");}
    else{setErr("Incorrect passkey.");setPk("");}
  }
  return <BottomSheet th={th} title="🔐 Manager Access" subtitle="Enter your passkey to view full details." onClose={p.onClose}>
    <input type="password" inputMode="numeric" maxLength={6} placeholder="Passkey" value={pk}
      onChange={function(e){setPk(e.target.value);setErr("");}}
      onKeyDown={function(e){if(e.key==="Enter")tryUnlock();}}
      style={{...inp(th),fontSize:22,letterSpacing:8,textAlign:"center",marginBottom:8}}/>
    {err&&<ErrBox msg={err}/>}
    <div style={{display:"flex",gap:10,marginTop:4}}>
      <button onClick={p.onClose} style={{flex:1,padding:12,borderRadius:9,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:14,fontFamily:"'Barlow',sans-serif"}}>Cancel</button>
      <button onClick={tryUnlock} style={{flex:1,padding:12,borderRadius:9,border:"none",background:"#e8313a",color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>Unlock</button>
    </div>
  </BottomSheet>;
}

// ─── QR Code generator (simple SVG-based) ──────────────────────────────────────
function QRPlaceholder(p) {
  var th=p.th;
  return <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:10,padding:20}}>
    <div style={{width:160,height:160,background:th.name==="dark"?"#fff":"#000",borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",padding:12}}>
      <div style={{width:"100%",height:"100%",background:th.name==="dark"?"#000":"#fff",borderRadius:4,display:"grid",gridTemplateColumns:"repeat(8,1fr)",gap:1,padding:4}}>
        {Array.from({length:64}).map(function(_,i){
          var row=Math.floor(i/8),col=i%8;
          var isCorner=(row<3&&col<3)||(row<3&&col>4)||(row>4&&col<3);
          var filled=isCorner||(Math.random()>0.5);
          return <div key={i} style={{background:filled?(th.name==="dark"?"#fff":"#000"):"transparent",borderRadius:1}}/>;
        })}
      </div>
    </div>
    <div style={{fontSize:11,color:th.muted,textAlign:"center",lineHeight:1.5}}>
      Scan to sign up at<br/>
      <span style={{color:th.text,fontWeight:700}}>{p.storeName||"this store"}</span>
    </div>
    <div style={{fontSize:9,color:th.faint}}>Store pre-selected on scan</div>
  </div>;
}

