function OnboardingScreen(p) {
  var th=p.th; var role=p.role;
  var [step,setStep]=useState(0);
  var slides=isAllPro({role:role})?[
    {icon:"📷",title:"Your job, simplified",body:"Find each vehicle on the lot, record a short walkaround, and save it. The video is permanently attached to that car's stock number and instantly available to the sales team."},
    {icon:"📋",title:"Shot list keeps you organized",body:"The app shows you a daily shot list of every car that needs video. Work through it like a checklist. Mark cars as assessed even before you film so nothing gets missed."},
    {icon:"🚩",title:"Quality flags and billing",body:"All-Pro QC reviews your uploads. If a video needs a reshoot you will see a flag with the exact reason. Every video you record is auto-logged for billing — no paperwork."},
  ]:isQC({role:role})?[
    {icon:"🔍",title:"Quality control across all stores",body:"Your QC feed shows every All-Pro video uploaded at every Sonic location. Review them, approve the ones that pass, and flag the ones that need reshoot with a specific reason."},
    {icon:"🏢",title:"Browse any store",body:"Switch between any Sonic location using the store picker. See their full inventory, video coverage, and pending reviews all in one place."},
    {icon:"✓",title:"Three simple statuses",body:"Every video is Pending, Approved, or Needs Reshoot. Work through Pending videos each session. Photographers see your flags instantly and know exactly what to fix."},
  ]:[
    {icon:"🚗",title:"Your inventory, always ready",body:"Every car on your lot loads automatically. Search by VIN, stock number, make, model, or color. All-Pro videos are already attached and ready to send."},
    {icon:"📹",title:"Professional videos at your fingertips",body:"All-Pro photographers shoot Official walkarounds for every vehicle. You find the car, they already filmed it. Your job is to send it personally."},
    {icon:"⬆️",title:"Send it in seconds",body:"Tap Send, type the customer's name, and the message is pre-written for you. One tap sends the video from your phone — the customer receives it from you personally."},
  ];
  var slide=slides[step];
  return <div style={{...rootStyle(th)}}>
    <style>{getGS(th)}</style>
    <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"32px 28px",textAlign:"center"}}>
      <div style={{fontSize:64,marginBottom:20}}>{slide.icon}</div>
      <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:26,fontWeight:800,color:th.text,letterSpacing:0.5,marginBottom:12}}>{slide.title}</div>
      <div style={{fontSize:15,color:th.sub,lineHeight:1.7,maxWidth:300}}>{slide.body}</div>
      <div style={{display:"flex",gap:8,marginTop:32}}>
        {slides.map(function(_,i){
          return <div key={i} style={{width:i===step?24:8,height:8,borderRadius:4,background:i===step?"#e8313a":th.border2,transition:"all 0.2s"}}/>;
        })}
      </div>
    </div>
    <div style={{padding:"14px 24px 36px",background:th.panel,borderTop:"1px solid "+th.border,display:"flex",gap:12}}>
      {step>0&&<button onClick={function(){setStep(function(s){return s-1;});}} style={{flex:1,padding:13,borderRadius:10,border:"1px solid "+th.border2,background:"transparent",color:th.sub,cursor:"pointer",fontSize:15,fontFamily:"'Barlow',sans-serif"}}>← Back</button>}
      <button onClick={function(){step<slides.length-1?setStep(function(s){return s+1;}):p.onDone();}} style={{...pbtn(),flex:2}}>
        {step<slides.length-1?"Next →":"Get Started →"}
      </button>
    </div>
  </div>;
}

// ─── Auth Screen ───────────────────────────────────────────────────────────────
function AuthScreen(p) {
  var path=p.path; var th=p.th;
  var isAP=path==="allpro"; var isQP=path==="qc";
  var isSC=path==="sonic-corp"; var isAC=path==="allpro-corp"; var isSA=path==="sonic-admin";
  var isCorpPath=isSC||isAC||isSA;
  var roles=isAP?[ALLPRO_ROLE]:isQP?[QC_ROLE]:isSC?[SONIC_CORP_ROLE]:isAC?[ALLPRO_CORP_ROLE]:isSA?[SONIC_ADMIN_ROLE]:SALES_ROLES;
  var pc=isAP?"#ff6b35":isQP?"#c084fc":isSC?"#ffd700":isAC?"#00d97e":isSA?"#9ca3af":"#4da6ff";
  var pl=isAP?"All-Pro Photographer":isQP?"All-Pro QC":isSC?"Sonic Corporate":isAC?"All-Pro Corporate":isSA?"Sonic Platform Admin":"Sales Staff";
  var corpCode=isSC?SONIC_CORP_CODE:isAC?ALLPRO_CORP_CODE:isSA?SONIC_ADMIN_CODE:null;
  var corpDomain=isSC?"sonicautomotive.com":isAC?["allprorecon.com","allproreconditioning.com"]:isSA?"sonicautomotive.com":null;

  var [tab,setTab]=useState("login");
  var [name,setName]=useState(""); var [email,setEmail]=useState(""); var [pw,setPw]=useState("");
  var [role,setRole]=useState(roles[0]); var [dealerId,setDealer]=useState("");
  var [invCode,setInvCode]=useState("");
  var [err,setErr]=useState(""); var [info,setInfo]=useState("");
  var [sentCode,setSent]=useState(""); var [pending,setPending]=useState(null);
  var [digits,setDigits]=useState(["","","","","",""]);
  var [step,setStep]=useState("form");
  var [faceIdPrompt,setFaceIdPrompt]=useState(null); // user object pending Face ID enable
  var [faceIdBusy,setFaceIdBusy]=useState(false);
  var [resetMode,setResetMode]=useState(false);
  var [resetSent,setResetSent]=useState(false);
  var [resetCode,setResetCode]=useState("");
  var [resetCodeInput,setResetCodeInput]=useState("");
  var [newPw1,setNewPw1]=useState(""); var [newPw2,setNewPw2]=useState("");
  var [resetBusy,setResetBusy]=useState(false);
  var faceIdEmail=getFaceIdEmail();
  var faceIdEnabledHere=faceIdAvailable()&&!!faceIdEmail;
  var d0=useRef(),d1=useRef(),d2=useRef(),d3=useRef(),d4=useRef(),d5=useRef();
  var dRefs=[d0,d1,d2,d3,d4,d5];
  // QR code store pre-selection
  useEffect(function(){
    if(p.preselectedStore){setDealer(p.preselectedStore);}
  },[p.preselectedStore]);

  function clr(){setErr("");setInfo("");}
  function doLogin(){
    clr();
    if(!email||!pw)return setErr("Enter your email and password.");
    var rate=checkLoginRate(email.toLowerCase());
    if(!rate.allowed)return setErr("Account locked for "+rate.mins+" minute"+(rate.mins!==1?"s":"")+" due to too many failed attempts.");
    // Check guest accounts
    var ga=_db.guestAccounts[email.toLowerCase()];
    if(ga){
      if(new Date()>new Date(ga.expiresAt))return setErr("This guest account has expired.");
      if(ga.password!==pw)return setErr("Incorrect password.");
      saveSession(ga); p.onLogin(ga); return;
    }
    var u=getUsers()[email.toLowerCase()];
    if(!u){recordLoginFail(email.toLowerCase());return setErr("No account found with that email.");}
    if(!u.verified){recordLoginFail(email.toLowerCase());return setErr("Account not verified. Check your email for the code.");}
    if(u.banned)return setErr("This account has been banned"+(u.banReason?": "+u.banReason:".")+" Contact your administrator.");
    if(u.deactivated)return setErr("This account has been deactivated. Contact your administrator.");
    if(u.password!==pw){recordLoginFail(email.toLowerCase());return setErr("Incorrect password. "+(checkLoginRate(email.toLowerCase()).remaining)+" attempt"+(checkLoginRate(email.toLowerCase()).remaining!==1?"s":"")+" remaining.");}
    clearLoginAttempts(email.toLowerCase());
    if(isQP&&u.role!==QC_ROLE)return setErr("This is not a QC account.");
    if(isAP&&u.role!==ALLPRO_ROLE)return setErr("This is not an All-Pro account.");
    if(!isAP&&!isQP&&(u.role===ALLPRO_ROLE||u.role===QC_ROLE))return setErr("Please use the correct login path.");
    addAudit({type:"login",user:u.email,store:u.dealerId});
    saveSession(u);
    if(faceIdAvailable()&&getFaceIdEmail()!==u.email.toLowerCase()){
      setFaceIdPrompt(u);
    }else{
      p.onLogin(u);
    }
  }
  async function doSendReset(){
    clr();
    if(!email||!email.includes("@"))return setErr("Enter the email address for your account.");
    var users=getUsers();
    var u=users[email.toLowerCase()];
    if(!u)return setErr("No account found with that email.");
    var code=randCode();
    setResetCode(code);
    if(isDemoMode()){
      setResetSent(true);
      setInfo("Demo Mode: your reset code is "+code+".");
      return;
    }
    setResetBusy(true);
    setInfo("📧 Sending reset code to "+email+"…");
    var sendRes=await sendVerificationEmail(email, code, u.name);
    setResetBusy(false);
    if(sendRes.ok){
      setResetSent(true);
      setInfo("📧 Code sent to "+email+". Enter it below with your new password.");
    }else{
      setResetSent(true);
      setInfo("Couldn't send the email, but here's your code: "+code+".");
    }
  }
  function doResetPassword(){
    clr();
    if(resetCodeInput.trim()!==resetCode)return setErr("Incorrect reset code.");
    if(newPw1.length<6)return setErr("Password must be at least 6 characters.");
    if(newPw1!==newPw2)return setErr("Passwords do not match.");
    var users=getUsers();
    var u=users[email.toLowerCase()];
    if(!u)return setErr("No account found with that email.");
    u.password=newPw1;
    users[email.toLowerCase()]=u;
    saveUsers(users);
    clearLoginAttempts(email.toLowerCase());
    setResetMode(false); setResetSent(false); setResetCode(""); setResetCodeInput(""); setNewPw1(""); setNewPw2(""); setPw("");
    setInfo("Password updated! Sign in with your new password below.");
  }
  function doDemo(){
    clr();
    var demoRole=isAP?ALLPRO_ROLE:isQP?QC_ROLE:isSC?SONIC_CORP_ROLE:isAC?ALLPRO_CORP_ROLE:isSA?SONIC_ADMIN_ROLE:"Sales";
    var demoStore=isQP?"allpro-qc":isSC?"sonic-corporate":isAC?"allpro-corporate":"massey-cadillac-orlando";
    var demoStoreName=isQP?"All-Pro QC":isSC?"Sonic Automotive Corporate":isAC?"All-Pro Corporate":isSA?"Sonic Automotive \u2014 Platform Admin":"Massey Cadillac of Orlando";
    var demoUser={
      email:"demo-"+(demoRole.toLowerCase().replace(/[^a-z]/g,""))+"@demo.videovault",
      password:"", name:(pl||"Demo")+" (Demo)", role:demoRole,
      dealerId:demoStore, dealerName:demoStoreName, dealerCity:isQP||isCorpPath?"Network-Wide":"Orlando, FL",
      verified:true, isDemo:true,
      termsVersion:TERMS_VERSION, hasOnboarded:true,
      profilePhoto:null, displayName:null,
      stores:[demoStore], activeStore:demoStore,
    };
    addAudit({type:"demo_login",user:demoUser.email,store:demoUser.dealerId,role:demoRole});
    p.onLogin(demoUser);
  }
  async function enableFaceId(){
    if(!faceIdPrompt)return;
    setFaceIdBusy(true);
    var res=await registerFaceId(faceIdPrompt.email,faceIdPrompt.displayName||faceIdPrompt.name);
    setFaceIdBusy(false);
    var u=faceIdPrompt; setFaceIdPrompt(null);
    p.onLogin(u);
  }
  function skipFaceId(){
    var u=faceIdPrompt; setFaceIdPrompt(null);
    if(u)p.onLogin(u);
  }
  async function faceIdLogin(){
    var em=getFaceIdEmail();
    if(!em)return;
    setFaceIdBusy(true); clr();
    var res=await verifyFaceId(em);
    setFaceIdBusy(false);
    if(!res.ok)return setErr(res.err);
    var u=getUsers()[em];
    if(!u)return setErr("Account not found. Use your password.");
    addAudit({type:"login",user:u.email,store:u.dealerId,via:"faceid"});
    saveSession(u); p.onLogin(u);
  }
  async function doSignup(){
    clr();
    if(!name.trim())return setErr("Enter your full name.");
    if(!email.includes("@"))return setErr("Enter a valid work email.");
    if(!isAllowedEmail(email))return setErr("This app is restricted to authorized Sonic Automotive and All-Pro Reconditioning email addresses. Contact your manager if you believe this is an error.");
    if(pw.length<6)return setErr("Password must be at least 6 characters.");
    if(isQP&&invCode.trim().toUpperCase()!==QC_INVITE_CODE)return setErr("Invalid invite code. Contact All-Pro management.");
    if(!isQP&&!isCorpPath&&role==="Manager"&&invCode.trim().toUpperCase()!==MANAGER_INVITE_CODE)return setErr("Invalid manager invite code. Contact your General Manager.");
    if(isCorpPath){
      if(invCode.trim().toUpperCase()!==corpCode)return setErr("Invalid corporate access code. Contact your administrator.");
      var emailDomain=email.toLowerCase().split("@")[1]||"";
      var domainOk=(isSA&&email.toLowerCase()===MASTER_ADMIN_EMAIL)||(Array.isArray(corpDomain)?corpDomain.indexOf(emailDomain)!==-1:emailDomain===corpDomain);
      if(!domainOk)return setErr("Corporate access requires a "+(Array.isArray(corpDomain)?corpDomain.join(" or "):corpDomain)+" email address.");
    }
    if(!isQP&&!isCorpPath&&!dealerId)return setErr("Select your dealership.");
    var users=getUsers();
    if(users[email.toLowerCase()]&&users[email.toLowerCase()].verified)return setErr("Account already exists. Try signing in.");
    var d=(!isQP&&!isCorpPath)?SONIC_DEALERS.find(function(x){return x.id===dealerId;}):null;
    var newAccount={
      email:email.toLowerCase(),password:pw,name:name.trim(),role:role,
      dealerId:isQP?"allpro-qc":isSC?"sonic-corporate":isAC?"allpro-corporate":isSA?"massey-cadillac-orlando":dealerId,
      dealerName:isQP?"All-Pro QC":isSC?"Sonic Automotive Corporate":isAC?"All-Pro Corporate":isSA?"Sonic Automotive — Platform Admin":d.name,
      dealerCity:isQP?"All Stores":isCorpPath?"Network-Wide":d.city,
      verified:false,
      termsVersion:TERMS_VERSION,
      termsAcceptedAt:new Date().toISOString(),
      createdAt:new Date().toISOString(),
      profilePhoto:null,displayName:null,
      stores:[isQP?"allpro-qc":isSC?"sonic-corporate":isAC?"allpro-corporate":isSA?"massey-cadillac-orlando":dealerId],
      activeStore:isQP?"allpro-qc":isSC?"sonic-corporate":isAC?"allpro-corporate":isSA?"massey-cadillac-orlando":dealerId,
    };

    // Demo Mode: skip email verification entirely — auto-confirm and sign in
    if(isDemoMode()){
      var verified0=Object.assign({},newAccount,{verified:true});
      var users0=getUsers(); users0[verified0.email]=verified0; saveUsers(users0);
      addAudit({type:"signup",user:verified0.email,store:verified0.dealerId,demo:true});
      saveSession(verified0); p.onLogin(verified0);
      return;
    }

    var code=randCode(); setSent(code);
    setPending(newAccount);
    setDigits(["","","","","",""]); setStep("verify");
    setInfo("📧 Sending code to "+email+"...");
    var sendRes=await sendVerificationEmail(email, code, name.trim());
    if(sendRes.ok){
      setInfo("📧 Code sent to "+email+". Check your inbox (and spam folder).");
    }else{
      setInfo("📧 Code sent to "+email+".\n\n🔑 Demo code: "+code+"\n(Email delivery isn't configured yet — showing code here so you can continue testing.)");
    }
  }
  function doVerify(){
    clr();
    var entered=digits.join("");
    if(entered.length<6)return setErr("Enter the full 6-digit code.");
    if(entered!==sentCode)return setErr("Incorrect code.");
    var users=getUsers();
    var verified=Object.assign({},pending,{verified:true});
    users[verified.email]=verified; saveUsers(users);
    addAudit({type:"signup",user:verified.email,store:verified.dealerId});
    saveSession(verified); p.onLogin(verified);
  }
  function onDigit(i,val){
    var v=val.replace(/\D/g,"").slice(-1);
    var next=digits.slice(); next[i]=v; setDigits(next);
    if(v&&i<5&&dRefs[i+1].current)dRefs[i+1].current.focus();
  }
  function onKey(i,e){
    if(e.key==="Backspace"&&!digits[i]&&i>0&&dRefs[i-1].current)dRefs[i-1].current.focus();
  }
  function onPaste(e){
    var paste=e.clipboardData.getData("text").replace(/\D/g,"").slice(0,6);
    if(paste.length===6){setDigits(paste.split(""));if(dRefs[5].current)dRefs[5].current.focus();e.preventDefault();}
  }

  if(faceIdPrompt){
    return <div style={{minHeight:"100vh",background:th.bg,display:"flex",flexDirection:"column",fontFamily:"'Barlow',sans-serif"}}>
      <style>{getGS(th)}</style>
      <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,maxWidth:420,width:"100%",margin:"0 auto",textAlign:"center"}}>
        <div style={{fontSize:64,marginBottom:16}}>🆔</div>
        <div style={{fontSize:20,fontWeight:800,color:th.text,fontFamily:"'Barlow Condensed',sans-serif",marginBottom:8}}>Enable Face ID?</div>
        <div style={{fontSize:13,color:th.muted,lineHeight:1.6,marginBottom:28}}>
          Sign in faster next time on this device using Face ID or Touch ID — no password needed.
        </div>
        <button onClick={enableFaceId} disabled={faceIdBusy} style={{...pbtn(pc),opacity:faceIdBusy?0.6:1,marginBottom:10}}>
          {faceIdBusy?"Setting up…":"Enable Face ID"}
        </button>
        <button onClick={skipFaceId} disabled={faceIdBusy} style={{width:"100%",padding:13,borderRadius:10,border:"none",background:"transparent",color:th.muted,cursor:"pointer",fontSize:14,fontFamily:"'Barlow',sans-serif"}}>
          Not now
        </button>
      </div>
    </div>;
  }

  return <div style={{minHeight:"100vh",background:th.bg,display:"flex",flexDirection:"column",fontFamily:"'Barlow',sans-serif"}}>
    <style>{getGS(th)}</style>
    <div style={{...hdr(th),display:"flex",alignItems:"center",gap:12}}>
      <button onClick={p.onBack} style={backBtn(th)}>←</button>
      <div>
        <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:800,fontSize:18,letterSpacing:2,color:th.text}}>VIDEO VAULT</div>
        <div style={{fontSize:10,color:pc,fontWeight:700,letterSpacing:0.5}}>{pl}</div>
      </div>
    </div>
    {(isQP||isCorpPath)&&<div style={{margin:"14px 20px 0",maxWidth:460,width:"calc(100% - 40px)",marginLeft:"auto",marginRight:"auto",background:pc+"14",border:"1px solid "+pc+"40",borderRadius:10,padding:"10px 14px",fontSize:11.5,color:th.text,lineHeight:1.5,display:"flex",gap:8,alignItems:"flex-start"}}>
      <span style={{fontSize:14}}>🔒</span>
      <span><b>Private login.</b> This access point is restricted to authorized {isQP?"All-Pro QC":isSC?"Sonic Corporate":isAC?"All-Pro Corporate":"Sonic Platform Admin"} personnel only. Unauthorized access attempts may be logged and reviewed.</span>
    </div>}
    <div style={{flex:1,overflowY:"auto",padding:"24px 20px 48px",maxWidth:460,width:"100%",margin:"0 auto"}}>
      {step==="form"&&<div>
        <div style={{display:"flex",background:th.inp,borderRadius:10,padding:4,marginBottom:22}}>
          {[["login","Sign In"],["signup","Create Account"]].map(function(item){
            var tb=item[0]; var tl=item[1];
            return <button key={tb} onClick={function(){setTab(tb);clr();}} style={{flex:1,padding:"10px 0",background:tab===tb?th.panel:"transparent",border:"none",color:tab===tb?th.text:th.muted,cursor:"pointer",fontSize:14,fontWeight:600,fontFamily:"'Barlow',sans-serif",borderRadius:7}}>{tl}</button>;
          })}
        </div>
        {err&&<ErrBox msg={err}/>}
        {info&&<InfoBox msg={info}/>}
        {tab==="login"&&<div>
          {resetMode?<div>
            <div style={{fontSize:13,color:th.muted,lineHeight:1.6,marginBottom:16}}>
              Enter your account email{resetSent?", the reset code, and a new password":""} below.
            </div>
            <span style={lbl(th)}>Work Email</span>
            <input style={inp(th)} type="email" inputMode="email" autoCapitalize="none" placeholder="you@dealership.com" value={email} onChange={function(e){setEmail(e.target.value);}}/>
            {!resetSent&&<button onClick={doSendReset} disabled={resetBusy} style={{...pbtn(pc),marginTop:20,opacity:resetBusy?0.6:1}}>{resetBusy?"Sending…":"Send Reset Code"}</button>}
            {resetSent&&<div>
              <span style={lbl(th)}>6-Digit Code</span>
              <input style={inp(th)} inputMode="numeric" maxLength={6} placeholder="000000" value={resetCodeInput} onChange={function(e){setResetCodeInput(e.target.value.replace(/[^0-9]/g,""));}}/>
              <span style={lbl(th)}>New Password</span>
              <PwInput value={newPw1} onChange={setNewPw1} placeholder="Min. 6 characters" th={th}/>
              <span style={lbl(th)}>Confirm New Password</span>
              <PwInput value={newPw2} onChange={setNewPw2} onEnter={doResetPassword} placeholder="Re-enter new password" th={th}/>
              <button onClick={doResetPassword} style={{...pbtn(pc),marginTop:20}}>Reset Password →</button>
            </div>}
            <button onClick={function(){setResetMode(false);setResetSent(false);setResetCode("");setResetCodeInput("");setNewPw1("");setNewPw2("");clr();}} style={{width:"100%",padding:13,borderRadius:10,border:"none",background:"transparent",color:th.muted,cursor:"pointer",fontSize:13,fontFamily:"'Barlow',sans-serif",marginTop:14}}>← Back to Sign In</button>
          </div>:<>
          {faceIdEnabledHere&&<button onClick={faceIdLogin} disabled={faceIdBusy} style={{width:"100%",padding:"14px 0",borderRadius:12,border:"1px solid "+pc+"55",background:pc+"12",color:pc,cursor:"pointer",fontSize:14,fontWeight:700,fontFamily:"'Barlow',sans-serif",marginBottom:16,display:"flex",alignItems:"center",justifyContent:"center",gap:8,opacity:faceIdBusy?0.6:1}}>
            <span style={{fontSize:18}}>🆔</span> {faceIdBusy?"Verifying…":"Sign in with Face ID"}
          </button>}
          {faceIdEnabledHere&&<div style={{textAlign:"center",fontSize:11,color:th.faint,marginBottom:16}}>— or sign in with password —</div>}
          <span style={lbl(th)}>Work Email</span>
          <input style={inp(th)} type="email" inputMode="email" autoCapitalize="none" placeholder="you@dealership.com" value={email} onChange={function(e){setEmail(e.target.value);}}/>
          <span style={lbl(th)}>Password</span>
          <PwInput value={pw} onChange={setPw} onEnter={doLogin} placeholder="••••••••" th={th}/>
          <button onClick={doLogin} style={{...pbtn(pc),marginTop:20}}>Sign In →</button>
          <button onClick={function(){setResetMode(true);clr();}} style={{width:"100%",padding:"10px 0",border:"none",background:"transparent",color:th.faint,cursor:"pointer",fontSize:12,fontFamily:"'Barlow',sans-serif",textDecoration:"underline",marginTop:10}}>Forgot password?</button>
          </>}
        </div>}
        {tab==="signup"&&<div>
          <span style={lbl(th)}>Full Name</span>
          <input style={inp(th)} placeholder="Your name" value={name} onChange={function(e){setName(e.target.value);}}/>
          <span style={lbl(th)}>Work Email</span>
          <input style={inp(th)} type="email" inputMode="email" autoCapitalize="none" placeholder="you@dealership.com" value={email} onChange={function(e){setEmail(e.target.value);}}/>
          <span style={lbl(th)}>Password</span>
          <PwInput value={pw} onChange={setPw} placeholder="Min. 6 characters" th={th}/>
          {!isAP&&!isQP&&<div>
            <span style={lbl(th)}>Your Role</span>
            <select style={inp(th)} value={role} onChange={function(e){setRole(e.target.value);setInvCode("");}}>
              {roles.map(function(r){return <option key={r} value={r}>{r}</option>;})}
            </select>
          </div>}
          {!isAP&&!isQP&&!isCorpPath&&role==="Manager"&&<div>
            <span style={lbl(th)}>Manager Invite Code</span>
            <input style={{...inp(th),letterSpacing:2}} placeholder="Enter your manager invite code" value={invCode} onChange={function(e){setInvCode(e.target.value.toUpperCase());}}/>
            <div style={{fontSize:10,color:th.muted,marginTop:4}}>Manager accounts require an invite code from your General Manager.</div>
          </div>}
          {isQP&&<div>
            <span style={lbl(th)}>Invite Code</span>
            <input style={{...inp(th),letterSpacing:2}} placeholder="Enter your QC invite code" value={invCode} onChange={function(e){setInvCode(e.target.value.toUpperCase());}}/>
            <div style={{fontSize:10,color:th.muted,marginTop:4}}>Contact All-Pro management if you do not have a code.</div>
          </div>}
          {isCorpPath&&<div>
            <span style={lbl(th)}>Corporate Access Code</span>
            <input style={{...inp(th),letterSpacing:2}} placeholder={isSC?"Enter Sonic Corporate code":"Enter All-Pro Corporate code"} value={invCode} onChange={function(e){setInvCode(e.target.value.toUpperCase());}}/>
            <div style={{fontSize:10,color:th.muted,marginTop:4}}>Issued by Sonic Automotive / All-Pro leadership only. Requires a {Array.isArray(corpDomain)?corpDomain.join(" or "):corpDomain} email address.</div>
          </div>}
          {!isQP&&!isCorpPath&&<div>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={lbl(th)}>Your Dealership</span>
              <span style={{fontSize:9,color:th.faint,marginTop:12}}>{SONIC_DEALERS.length} locations</span>
            </div>
            <DealerPicker dealerId={dealerId} setDealerId={setDealer} th={th}/>
          </div>}
          <button onClick={doSignup} style={{...pbtn(pc),marginTop:20}}>Send Confirmation Code →</button>
        </div>}
        {!resetMode&&<div style={{textAlign:"center",marginTop:22,paddingTop:16,borderTop:"1px solid "+th.border}}>
          <button onClick={doDemo} style={{background:"none",border:"none",color:th.faint,fontSize:11.5,cursor:"pointer",fontFamily:"'Barlow',sans-serif",textDecoration:"underline"}}>Explore in demo mode</button>
          <div style={{fontSize:9.5,color:th.faint,opacity:0.6,marginTop:5,lineHeight:1.4}}>Browse a sample {pl} account. No data is saved.</div>
        </div>}
      </div>}
      {step==="verify"&&<div>
        <div style={{textAlign:"center",marginBottom:22}}>
          <div style={{fontSize:44,marginBottom:10}}>📧</div>
          <div style={{fontSize:18,fontWeight:700,color:th.text,marginBottom:6}}>Check your email</div>
          <div style={{fontSize:13,color:th.muted,lineHeight:1.5}}>We sent a 6-digit code to<br/><span style={{color:th.text,fontWeight:600}}>{email}</span></div>
        </div>
        {info&&<InfoBox msg={info}/>}
        {err&&<ErrBox msg={err}/>}
        <div style={{display:"flex",gap:8,justifyContent:"center",margin:"8px 0 22px"}}>
          {digits.map(function(d,i){
            return <input key={i} ref={dRefs[i]}
              style={{width:46,height:58,textAlign:"center",fontSize:24,fontWeight:700,background:th.inp,border:"2px solid "+(d?pc:th.border),borderRadius:10,color:th.text,outline:"none",fontFamily:"'Barlow',sans-serif"}}
              inputMode="numeric" maxLength={1} value={d}
              onChange={function(e){onDigit(i,e.target.value);}}
              onKeyDown={function(e){onKey(i,e);}}
              onPaste={onPaste}/>;
          })}
        </div>
        <button onClick={doVerify} style={pbtn(pc)}>Verify and Create Account →</button>
        <div style={{display:"flex",justifyContent:"space-between",marginTop:14}}>
          <button onClick={function(){setStep("form");clr();setDigits(["","","","","",""]);}} style={{background:"none",border:"none",color:th.muted,fontSize:13,cursor:"pointer",fontFamily:"'Barlow',sans-serif"}}>← Back</button>
          <button onClick={async function(){
            var c=randCode();setSent(c);setDigits(["","","","","",""]);
            setInfo("📧 Sending new code...");
            var sendRes=await sendVerificationEmail(email, c, pending&&pending.name);
            if(sendRes.ok)setInfo("📧 New code sent to "+email+".");
            else setInfo("📧 New code: "+c+"\n(Email delivery isn't configured yet — showing code here so you can continue testing.)");
          }} style={{background:"none",border:"none",color:pc,fontSize:13,cursor:"pointer",fontFamily:"'Barlow',sans-serif"}}>Resend code</button>
        </div>
      </div>}
    </div>
  </div>;
}

