// ─── Share Composer ────────────────────────────────────────────────────────────
function ShareComposer(p) {
  var vid=p.vid; var vehicle=p.vehicle; var sender=p.sender; var th=p.th;
  var [lang,setLang]=useState(p.defaultLang||"en");
  var [custName,setCust]=useState(p.prefillName||"");
  var [custContact,setCtc]=useState(p.prefillContact||"");
  var [msg,setMsg]=useState("");
  var [sending,setSending]=useState(false);
  var [showTemplates,setShowTemplates]=useState(false);
  var [followUp,setFollowUp]=useState(true);
  var [followUpDays,setFollowUpDays]=useState(2);
  var templates=p.templates||[];
  var sentNames=p.sentNames||[];

  var alreadySent=custName.trim().length>2&&sentNames.some(function(n){return n.toLowerCase()===custName.trim().toLowerCase();});

  // Check blackout hours
  var now=new Date();
  var hr=now.getHours();
  var storeSettings=getStoreSettings(p.dealerId||"");
  var blackoutStart=storeSettings.blackoutStart||BLACKOUT_START;
  var blackoutEnd=storeSettings.blackoutEnd||BLACKOUT_END;
  var inBlackout=hr>=blackoutStart||hr<blackoutEnd;

  function buildMsg(n,l){
    var nm=n||"there";
    var carStr=vehicle?(vehicle.year+" "+vehicle.make+" "+vehicle.model+" "+(vehicle.trim||"")):"the vehicle";
    var stockStr=vehicle?("Stock #"+vehicle.stock):"";
    if(l==="es")return "Hola "+nm+", acabo de preparar un video personal del "+carStr+" en el que estabas interesado - "+stockStr+".\n\nEchale un vistazo y dime que te parece.\n\n- "+sender;
    return "Hi "+nm+", I just pulled up a personal video of the "+carStr+" you were interested in - "+stockStr+".\n\nTake a look and let me know what you think!\n\n- "+sender;
  }
  useEffect(function(){setMsg(buildMsg(custName,lang));},[]); // eslint-disable-line

  function handleSend(){
    if(inBlackout){
      if(!window.confirm("Store blackout hours are active ("+blackoutStart+":00 - "+blackoutEnd+":00). Send anyway?"))return;
    }
    // First-send brand acknowledgment
    if(!_db.brandAckDone){
      if(!window.confirm("By sending this video you confirm it represents Sonic Automotive brand standards — accurate, professional, and appropriate for the customer.\n\nThis message will not appear again.")){return;}
      _db.brandAckDone=true;
    }
    setSending(true);
    if(vid.isDemo){
      setTimeout(function(){
        setSending(false);
        p.onSend({custName:custName||"Customer",custContact:custContact,msg:msg,sentAt:new Date().toISOString(),followUpDays:followUp?followUpDays:null});
      },800);
      return;
    }
    var mt=(vid.blob.type||"").toLowerCase();
    // Reuse the original file extension if the blob is an uploaded File (most reliable —
    // matches the actual container format, e.g. .mov from an iPhone Camera roll upload).
    var origName=vid.blob.name||"";
    var origExt=origName?(origName.match(/\.[^/.]+$/)||[""])[0].toLowerCase():"";
    var ext;
    if(mt.includes("mp4"))ext=".mp4";
    else if(mt.includes("quicktime"))ext=".mov";
    else if(mt.includes("webm"))ext=".webm";
    else if(mt.includes("png"))ext=".png";
    else if(mt.includes("jpeg")||mt.includes("jpg"))ext=".jpg";
    else if(mt.includes("image"))ext=".img";
    else if(origExt)ext=origExt;
    else ext=".mp4"; // safer default than .webm — iOS can't play .webm at all
    var file=new File([vid.blob],vid.name+ext,{type:vid.blob.type||(ext===".mov"?"video/quicktime":ext===".mp4"?"video/mp4":"application/octet-stream")});
    var doShare=function(){
      if(navigator.share&&navigator.canShare&&navigator.canShare({files:[file]})){
        navigator.share({title:vehicle?(vehicle.year+" "+vehicle.make+" "+vehicle.model):"Video",text:msg,files:[file]})
          .then(function(){finish();})
          .catch(function(err){if(err.name==="AbortError"){setSending(false);return;}finish();});
      }else{finish();}
    };
    function finish(){
      try{navigator.clipboard.writeText(msg);}catch(e){}
      var a=document.createElement("a");a.href=URL.createObjectURL(vid.blob);a.download=vid.name+ext;a.click();
      setSending(false);
      p.onSend({custName:custName||"Customer",custContact:custContact,msg:msg,sentAt:new Date().toISOString(),followUpDays:followUp?followUpDays:null});
    }
    doShare();
  }

  var charCount=msg.length;
  var charWarn=charCount>600;

  return <div style={rootStyle(th)}>
    <style>{getGS(th)}</style>
    <div style={{...hdr(th),display:"flex",alignItems:"center",gap:12}}>
      <button onClick={p.onClose} style={backBtn(th)}>←</button>
      <div style={{flex:1}}>
        <div style={{fontSize:15,fontWeight:700,color:th.text}}>Send Video</div>
        <div style={{fontSize:11,color:th.muted}}>{vehicle?(vehicle.year+" "+vehicle.make+" "+vehicle.model+" · #"+vehicle.stock):""}</div>
      </div>
      <VTypeBadge type={vid.videoType} small={true}/>
    </div>
    <div style={{flex:1,overflowY:"auto",padding:16}}>
      {vid.isDemo&&<InfoBox msg="🎬 Demo mode — in production the video file attaches directly." accent="#ffd700"/>}
      {inBlackout&&<div style={{background:"#e8313a12",border:"1px solid #e8313a33",borderRadius:9,padding:"8px 12px",marginBottom:12,fontSize:12,color:"#e8313a"}}>⏰ Store blackout hours active — sends are discouraged until {blackoutEnd}:00 AM</div>}
      {alreadySent&&<div style={{background:"#ffd70012",border:"1px solid #ffd70033",borderRadius:9,padding:"8px 12px",marginBottom:12,fontSize:12,color:"#ffd700"}}>⚠ You may have already sent a video to {custName} for this vehicle. Check the sent log.</div>}

      {/* Language toggle */}
      <div style={{display:"flex",gap:6,marginBottom:12}}>
        {[["en","🇺🇸 English"],["es","🇪🇸 Español"]].map(function(item){
          var l=item[0]; var lbl2=item[1];
          return <button key={l} onClick={function(){setLang(l);setMsg(buildMsg(custName,l));}} style={{flex:1,padding:"8px 0",background:lang===l?"#4da6ff18":"transparent",border:lang===l?"1px solid #4da6ff55":"1px solid "+th.border,borderRadius:8,color:lang===l?"#4da6ff":th.muted,fontSize:12,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700}}>{lbl2}</button>;
        })}
      </div>

      <span style={lbl(th)}>Customer Name</span>
      <input style={inp(th)} placeholder={lang==="es"?"Ej. Juan Garcia":"e.g. John Smith"} value={custName} onChange={function(e){setCust(e.target.value);setMsg(buildMsg(e.target.value,lang));}}/>

      <span style={lbl(th)}>{lang==="es"?"Telefono o Correo (opcional)":"Phone or Email (optional)"}</span>
      <input style={inp(th)} placeholder={lang==="es"?"Para sus registros":"For your records"} value={custContact} onChange={function(e){setCtc(e.target.value);}}/>

      {/* Templates */}
      {templates.length>0&&<div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:12,marginBottom:4}}>
          <span style={lbl(th)}>Message</span>
          <button onClick={function(){setShowTemplates(true);}} style={{background:"transparent",border:"none",color:"#4da6ff",fontSize:11,cursor:"pointer",fontFamily:"'Barlow',sans-serif"}}>📋 Templates</button>
        </div>
      </div>}
      {templates.length===0&&<span style={lbl(th)}>Message</span>}

      <textarea value={msg} onChange={function(e){setMsg(e.target.value);}} style={{...inp(th),height:160,resize:"none",lineHeight:1.55,fontSize:14}}/>
      <div style={{display:"flex",justifyContent:"space-between",marginTop:4,marginBottom:12}}>
        <div style={{fontSize:9,color:th.faint}}>Pre-written · edit freely</div>
        <div style={{fontSize:9,color:charWarn?"#ffd700":th.faint}}>{charCount} chars{charWarn?" — may be truncated by some apps":""}</div>
      </div>

      <div style={{background:th.inp,border:"1px solid "+th.border,borderRadius:9,padding:"10px 14px",fontSize:12,color:th.muted,lineHeight:1.5}}>
        📎 {lang==="es"?"En movil el video se adjunta directamente.":"On mobile the video attaches directly. On desktop it downloads and the message copies to clipboard."}
      </div>
    </div>

    {showTemplates&&<BottomSheet th={th} title="📋 Your Templates" subtitle="Tap to use" onClose={function(){setShowTemplates(false);}}>
      {templates.map(function(t,i){
        return <div key={i} onClick={function(){setMsg(t.text.replace("{name}",custName||"there").replace("{car}",vehicle?(vehicle.year+" "+vehicle.make+" "+vehicle.model):"the vehicle").replace("{sender}",sender));setShowTemplates(false);}} style={{padding:"12px 0",borderBottom:"1px solid "+th.border,cursor:"pointer"}}>
          <div style={{fontSize:13,fontWeight:600,color:th.text,marginBottom:3}}>{t.name}</div>
          <div style={{fontSize:11,color:th.muted,lineHeight:1.4}}>{t.text.slice(0,80)}...</div>
        </div>;
      })}
      {templates.length===0&&<div style={{textAlign:"center",padding:20,color:th.faint}}>No templates saved yet. Save a message from the sent log.</div>}
    </BottomSheet>}

    <div style={{padding:"10px 16px 28px",background:th.panel,borderTop:"1px solid "+th.border,flexShrink:0}}>
      <div onClick={function(){setFollowUp(function(f){return !f;});}} style={{display:"flex",alignItems:"center",gap:10,marginBottom:12,cursor:"pointer"}}>
        <div style={{width:20,height:20,borderRadius:5,border:"2px solid "+(followUp?"#4da6ff":th.border2),background:followUp?"#4da6ff":"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
          {followUp&&<span style={{color:"#fff",fontSize:12,fontWeight:800}}>✓</span>}
        </div>
        <div style={{flex:1}}>
          <div style={{fontSize:12,color:th.text,fontWeight:600}}>{lang==="es"?"Recordatorio de seguimiento":"Set follow-up reminder"}</div>
        </div>
        {followUp&&<select onClick={function(e){e.stopPropagation();}} value={followUpDays} onChange={function(e){setFollowUpDays(Number(e.target.value));}} style={{background:th.inp,border:"1px solid "+th.border,borderRadius:6,color:"#4da6ff",fontSize:12,fontWeight:700,padding:"4px 8px",fontFamily:"'Barlow',sans-serif"}}>
          {[1,2,3,5,7,14].map(function(d){return <option key={d} value={d}>{d} day{d!==1?"s":""}</option>;})}
        </select>}
      </div>
      <button onClick={handleSend} disabled={sending} style={{...pbtn("#00d97e"),opacity:sending?0.6:1,fontSize:16}}>
        {sending?(lang==="es"?"Enviando...":"Sending..."):(lang==="es"?"⬆ Enviar a "+(custName||"Cliente"):"⬆ Send to "+(custName||"Customer"))}
      </button>
    </div>
  </div>;
}

// ─── Sent Log ──────────────────────────────────────────────────────────────────
function SentLog(p) {
  var th=p.th; var log=p.log; var vehicle=p.vehicle;
  var [unlocked,setUnlocked]=useState(false);
  var [unlockedAt,setUnlockedAt]=useState(null);
  var [showPK,setShowPK]=useState(false);
  // Auto-expire manager unlock after 5 minutes (SEC-03)
  useEffect(function(){
    if(!unlocked||!unlockedAt)return;
    var iv=setInterval(function(){
      if(Date.now()-unlockedAt>5*60*1000){setUnlocked(false);setUnlockedAt(null);}
    },15000);
    return function(){clearInterval(iv);};
  },[unlocked,unlockedAt]);
  var [filter,setFilter]=useState("All");

  var filtered=filter==="All"?log:log.filter(function(e){return e.outcome===filter;});

  function updateOutcome(idx,outcome){
    if(p.onUpdateOutcome)p.onUpdateOutcome(idx,outcome);
  }

  return <div style={rootStyle(th)}>
    <style>{getGS(th)}</style>
    {showPK&&<PasskeyModal th={th} dealerId={p.dealerId} onUnlock={function(){setUnlocked(true);setShowPK(false);}} onClose={function(){setShowPK(false);}}/>}
    <div style={{...hdr(th),display:"flex",alignItems:"center",gap:12}}>
      <button onClick={p.onClose} style={backBtn(th)}>←</button>
      <div style={{flex:1}}>
        <div style={{fontSize:15,fontWeight:700,color:th.text}}>Sent Log</div>
        <div style={{fontSize:11,color:th.muted}}>{vehicle?(vehicle.year+" "+vehicle.make+" "+vehicle.model+" · #"+vehicle.stock):""}</div>
      </div>
      <div style={{display:"flex",gap:8,alignItems:"center"}}>
        {p.isManager&&!unlocked&&<button onClick={function(){setShowPK(true);}} style={{background:"#e8313a18",border:"1px solid #e8313a44",color:"#e8313a",padding:"5px 10px",borderRadius:7,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>🔐 Unlock</button>}
        {unlocked&&<span style={{fontSize:10,color:"#00d97e",fontWeight:700}}>🔓 Full Access</span>}
        <span style={{fontSize:12,color:th.muted}}>{log.length}</span>
      </div>
    </div>

    {/* Outcome filter */}
    {log.length>0&&<div style={{background:th.panel,borderBottom:"1px solid "+th.border,padding:"8px 14px",display:"flex",gap:6,overflowX:"auto"}}>
      {["All","No Response","Responded","Visited","Sold"].map(function(f){
        var c=f==="All"?th.muted:(OUTCOME_COLORS[f]||th.muted);
        return <button key={f} onClick={function(){setFilter(f);}} style={{flexShrink:0,padding:"5px 12px",background:filter===f?c+"18":"transparent",border:filter===f?"1px solid "+c+"55":"1px solid "+th.border,borderRadius:7,color:filter===f?c:th.muted,fontSize:11,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700,whiteSpace:"nowrap"}}>{f}</button>;
      })}
    </div>}

    <div style={{flex:1,overflowY:"auto",padding:14}}>
      {filtered.length===0?(
        <div style={{textAlign:"center",padding:"60px 20px",color:th.faint}}>
          <div style={{fontSize:44,marginBottom:10}}>📤</div>
          <div>No sends yet</div>
        </div>
      ):filtered.slice().reverse().map(function(e,i){
        var realIdx=log.length-1-i;
        return <div key={i} style={{...card(th),padding:"12px 14px",marginBottom:10}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:6}}>
            <div>
              <div style={{fontSize:14,fontWeight:700,color:th.text,marginBottom:2}}>{e.custName}</div>
              <div style={{fontSize:11,color:th.muted}}>Sent by <span style={{color:ROLE_COLORS["Sales"]||"#4da6ff",fontWeight:600}}>{e.sentBy}</span> · {fmtDaysAgo(e.sentAt)}</div>
            </div>
            <VTypeBadge type={e.videoType||"Walk-around"} small={true}/>
          </div>
          {/* Outcome selector */}
          <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:8}}>
            {OUTCOMES.map(function(o){
              var oc=OUTCOME_COLORS[o];
              var active=e.outcome===o;
              return <button key={o} onClick={function(){updateOutcome(realIdx,o);}} style={{padding:"3px 9px",background:active?oc+"22":"transparent",border:"1px solid "+(active?oc+"55":th.border),borderRadius:5,color:active?oc:th.muted,fontSize:9,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700}}>{o}</button>;
            })}
          </div>
          {unlocked&&<div style={{borderTop:"1px solid "+th.border,paddingTop:8,marginTop:4}}>
            {e.custContact&&<div style={{fontSize:12,color:th.muted,marginBottom:6}}>📞 {e.custContact}</div>}
            <div style={{fontSize:11,color:th.muted,fontStyle:"italic",lineHeight:1.4}}>"{(e.msg||"").slice(0,160)}{(e.msg||"").length>160?"...":""}"</div>
          </div>}
          {!unlocked&&p.isManager&&<div style={{borderTop:"1px solid "+th.border,paddingTop:6,marginTop:4}}>
            <div style={{fontSize:10,color:th.faint,fontStyle:"italic"}}>🔐 Unlock to view message and contact</div>
          </div>}
        </div>;
      })}
    </div>
  </div>;
}

// ─── My Sends Screen ──────────────────────────────────────────────────────────
function MySends(p) {
  var th=p.th; var user=p.user; var sentLog=p.sentLog; var inventory=p.inventory;
  var [filter,setFilter]=useState("All");

  var allMySends=[];
  Object.keys(sentLog).forEach(function(vin){
    var veh=inventory.find(function(v){return v.vin===vin;});
    (sentLog[vin]||[]).forEach(function(e,idx){
      if(e.sentBy===user.name){
        allMySends.push(Object.assign({},e,{vin:vin,veh:veh,logIdx:idx}));
      }
    });
  });
  allMySends.sort(function(a,b){return new Date(b.sentAt||0)-new Date(a.sentAt||0);});

  var filtered=filter==="All"?allMySends:allMySends.filter(function(e){return e.outcome===filter;});

  return <div style={rootStyle(th)}>
    <style>{getGS(th)}</style>
    <div style={{...hdr(th),display:"flex",alignItems:"center",gap:12}}>
      <button onClick={p.onClose} style={backBtn(th)}>←</button>
      <div style={{flex:1}}>
        <div style={{fontSize:15,fontWeight:700,color:th.text}}>My Sends</div>
        <div style={{fontSize:11,color:th.muted}}>{allMySends.length} total · {allMySends.filter(function(e){return e.outcome==="Sold";}).length} sold</div>
      </div>
    </div>
    <div style={{background:th.panel,borderBottom:"1px solid "+th.border,padding:"8px 14px",display:"flex",gap:6,overflowX:"auto"}}>
      {["All","No Response","Responded","Visited","Sold"].map(function(f){
        var c=f==="All"?th.muted:(OUTCOME_COLORS[f]||th.muted);
        var cnt=f==="All"?allMySends.length:allMySends.filter(function(e){return e.outcome===f;}).length;
        return <button key={f} onClick={function(){setFilter(f);}} style={{flexShrink:0,padding:"5px 12px",background:filter===f?c+"18":"transparent",border:filter===f?"1px solid "+c+"55":"1px solid "+th.border,borderRadius:7,color:filter===f?c:th.muted,fontSize:11,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700,whiteSpace:"nowrap"}}>{f} ({cnt})</button>;
      })}
    </div>
    <div style={{flex:1,overflowY:"auto",padding:14}}>
      {filtered.length===0?(
        <div style={{textAlign:"center",padding:"60px 20px",color:th.faint}}>
          <div style={{fontSize:44,marginBottom:10}}>📤</div>
          <div>{filter==="All"?"No sends yet":"No "+filter.toLowerCase()+" sends"}</div>
        </div>
      ):filtered.map(function(e,i){
        var oc=OUTCOME_COLORS[e.outcome||"No Response"]||th.muted;
        return <div key={i} style={{...card(th),padding:"11px 14px",marginBottom:8}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
            <div style={{fontSize:13,fontWeight:700,color:th.text}}>{e.custName}</div>
            <OutcomeBadge outcome={e.outcome||"No Response"}/>
          </div>
          {e.veh&&<div style={{fontSize:11,color:th.muted,marginBottom:4}}>🚗 {e.veh.year} {e.veh.make} {e.veh.model} · #{e.veh.stock}</div>}
          <div style={{fontSize:10,color:th.faint,marginBottom:6}}>{fmtDaysAgo(e.sentAt)}</div>
          <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
            {OUTCOMES.map(function(o){
              var active=e.outcome===o;
              var oclr=OUTCOME_COLORS[o];
              return <button key={o} onClick={function(){if(p.onUpdateOutcome)p.onUpdateOutcome(e.vin,e.logIdx,o);}} style={{padding:"3px 8px",background:active?oclr+"22":"transparent",border:"1px solid "+(active?oclr+"55":th.border),borderRadius:5,color:active?oclr:th.muted,fontSize:9,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700}}>{o}</button>;
            })}
          </div>
        </div>;
      })}
    </div>
  </div>;
}

// ─── Billing Report ────────────────────────────────────────────────────────────
function BillingReport(p) {
  var th=p.th; var videos=p.videos; var inventory=p.inventory;
  var [startDate,setStart]=useState("");
  var [endDate,setEnd]=useState("");
  var [rf,setRf]=useState("All-Pro");
  var [mode,setMode]=useState("subscription"); // subscription | per-video

  var allVids=[];
  Object.keys(videos).forEach(function(vin){
    var veh=inventory.find(function(v){return v.vin===vin;});
    (videos[vin]||[]).forEach(function(v){
      if(!v.isDemo)allVids.push(Object.assign({},v,{vin:vin,veh:veh}));
    });
  });
  var filtered=allVids.filter(function(v){
    var matchRole=rf==="All-Pro"?v.role===ALLPRO_ROLE:true;
    var d=new Date(v.date||Date.now());
    var after=!startDate||d>=new Date(startDate);
    var before=!endDate||d<=new Date(endDate+"T23:59:59");
    return matchRole&&after&&before;
  }).sort(function(a,b){return new Date(b.date||0)-new Date(a.date||0);});

  var apCount=filtered.filter(function(v){return v.role===ALLPRO_ROLE;}).length;
  var perVideoTotal=apCount*2;

  function exportCSV(){
    var header="Date,Photographer,Role,Vehicle,Stock #,VIN,Video Type,Store,Charge";
    var rows=filtered.map(function(v){
      var charge=mode==="per-video"&&v.role===ALLPRO_ROLE?"$2.00":"";
      return [
        fmtDate(v.date||new Date()),v.uploader,v.role,
        v.veh?(v.veh.year+" "+v.veh.make+" "+v.veh.model):"Unknown",
        v.veh?v.veh.stock:v.vin,v.vin,v.videoType,p.dealerName,charge
      ].map(function(c){return '"'+String(c).replace(/"/g,'""')+'"';}).join(",");
    });
    var blob=new Blob([[header].concat(rows).join("\n"),"\n\n\"Total All-Pro Videos: "+apCount+"\",\"Est. Total: $"+perVideoTotal+"\""].join(""),{type:"text/csv"});
    var a=document.createElement("a");
    a.href=URL.createObjectURL(blob);
    a.download="VideoVault-Billing-"+p.dealerName.replace(/\s+/g,"-")+"-"+new Date().toISOString().slice(0,10)+".csv";
    a.click();
  }

  var summaryItems=[
    {val:apCount,label:"All-Pro Videos",clr:"#ff6b35"},
    {val:filtered.length,label:"Total Videos",clr:"#00d97e"},
    {val:"$"+perVideoTotal.toLocaleString(),label:"Est. @ $2/video",clr:"#ffd700"},
  ];

  return <div style={rootStyle(th)}>
    <style>{getGS(th)}</style>
    <div style={{...hdr(th)}}>
      <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
        <button onClick={p.onClose} style={backBtn(th)}>←</button>
        <div style={{flex:1}}>
          <div style={{fontSize:15,fontWeight:700,color:th.text}}>Billing Report</div>
          <div style={{fontSize:11,color:th.muted}}>{p.dealerName} · {p.dealerCity}</div>
        </div>
        <button onClick={exportCSV} style={{background:"#00d97e18",border:"1px solid #00d97e44",color:"#00d97e",padding:"7px 13px",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>↓ CSV</button>
      </div>
      {/* Billing mode toggle */}
      <div style={{display:"flex",gap:6,marginBottom:8}}>
        {[["subscription","📅 Subscription"],["per-video","📹 Per Video"]].map(function(item){
          var v=item[0]; var l=item[1];
          return <button key={v} onClick={function(){setMode(v);}} style={{flex:1,padding:"7px 0",background:mode===v?"#ffd70018":"transparent",border:mode===v?"1px solid #ffd70055":"1px solid "+th.border,borderRadius:7,color:mode===v?"#ffd700":th.muted,fontSize:11,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700}}>{l}</button>;
        })}
      </div>
      <div style={{display:"flex",gap:8,marginBottom:8}}>
        <div style={{flex:1}}>
          <span style={lbl(th)}>From</span>
          <input type="date" style={{...inp(th),padding:"8px 10px",fontSize:13}} value={startDate} onChange={function(e){setStart(e.target.value);}}/>
        </div>
        <div style={{flex:1}}>
          <span style={lbl(th)}>To</span>
          <input type="date" style={{...inp(th),padding:"8px 10px",fontSize:13}} value={endDate} onChange={function(e){setEnd(e.target.value);}}/>
        </div>
      </div>
      <div style={{display:"flex",gap:6}}>
        {[["All-Pro","All-Pro Only"],["All","All Staff"]].map(function(item){
          var val=item[0]; var lbl2=item[1];
          return <button key={val} onClick={function(){setRf(val);}} style={{flex:1,padding:"7px 0",background:rf===val?"#ff6b3518":"transparent",border:rf===val?"1px solid #ff6b3555":"1px solid "+th.border,borderRadius:7,color:rf===val?"#ff6b35":th.muted,fontSize:12,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700}}>{lbl2}</button>;
        })}
      </div>
    </div>
    <div style={{background:th.panel,borderBottom:"1px solid "+th.border,padding:"12px 16px",flexShrink:0}}>
      <div style={{display:"flex",gap:10}}>
        {summaryItems.map(function(item){
          return <div key={item.label} style={{flex:1,background:th.inp,border:"1px solid "+th.border,borderRadius:9,padding:"10px 14px"}}>
            <div style={{fontSize:22,fontWeight:800,color:item.clr,fontFamily:"'Barlow Condensed',sans-serif"}}>{item.val}</div>
            <div style={{fontSize:9,color:th.muted,textTransform:"uppercase",letterSpacing:1,marginTop:2}}>{item.label}</div>
          </div>;
        })}
      </div>
    </div>
    <div style={{flex:1,overflowY:"auto",padding:14}}>
      {filtered.length===0?(
        <div style={{textAlign:"center",padding:"60px 20px",color:th.faint}}>
          <div style={{fontSize:44,marginBottom:10}}>📋</div>
          <div>No entries match</div>
        </div>
      ):filtered.map(function(v,i){
        var isAP=v.role===ALLPRO_ROLE;
        var rc=ROLE_COLORS[v.role]||"#888";
        return <div key={i} style={{...card(th),padding:"11px 14px",marginBottom:8,display:"flex",gap:12,alignItems:"center"}}>
          <div style={{width:36,height:36,borderRadius:8,background:rc+"20",border:"1px solid "+rc+"44",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>{isAP?"📷":"🎬"}</div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:13,fontWeight:600,color:th.text,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{v.veh?(v.veh.year+" "+v.veh.make+" "+v.veh.model):v.vin}</div>
            <div style={{fontSize:10,color:th.muted,marginTop:2,display:"flex",gap:8}}>
              {v.veh&&<span>#{v.veh.stock}</span>}
              <span>{fmtDate(v.date||new Date())}</span>
              <span style={{color:rc}}>{v.uploader}</span>
            </div>
          </div>
          <div style={{flexShrink:0,textAlign:"right"}}>
            <VTypeBadge type={v.videoType} small={true}/>
            {isAP&&mode==="per-video"&&<div style={{fontSize:9,color:"#ffd700",fontWeight:700,marginTop:4}}>$2.00</div>}
          </div>
        </div>;
      })}
      <div style={{textAlign:"center",padding:"20px 0 8px",fontSize:9,color:th.faint,letterSpacing:1}}>POWERED BY VIDEO VAULT · SONIC AUTOMOTIVE EXCLUSIVE</div>
    </div>
  </div>;
}

// ─── QC Feed ───────────────────────────────────────────────────────────────────
function QCFeed(p) {
  var th=p.th; var videos=p.videos; var user=p.user;
  var [storeF,setStoreF]=useState("All");
  var [statusF,setStatusF]=useState("All");
  var [qcStatus,setQcStatus]=useState({}); // {vidId: "pending"|"approved"|"reshoot"}
  var [qcNotes,setQcNotes]=useState({});   // {vidId: "note text"}
  var [flags,setFlags]=useState({});       // {vidId: {reason, flaggedBy, flaggedAt}}
  var [flagging,setFlagging]=useState(null);
  var [flagReason,setFlagReason]=useState("");
  var [customReason,setCustomReason]=useState("");
  var [playVid,setPlayVid]=useState(null);
  var [showStores,setShowStores]=useState(false);
  var [storeInvView,setStoreInvView]=useState(false);
  var [noteFor,setNoteFor]=useState(null);
  var [noteText,setNoteText]=useState("");
  var [pendingAlert,setPendingAlert]=useState(false);
  var [mutedVids,setMutedVids]=useState({}); // {vidId: true/false}
  var [showExport,setShowExport]=useState(false);
  var [expStart,setExpStart]=useState(new Date().toISOString().slice(0,10));
  var [expEnd,setExpEnd]=useState(new Date().toISOString().slice(0,10));
  var [expStore,setExpStore]=useState("All");
  var [expAllProOnly,setExpAllProOnly]=useState(true);
  var [editingVid,setEditingVid]=useState(null); // video object being trimmed
  var [trimStart,setTrimStart]=useState(0);
  var [trimEnd,setTrimEnd]=useState(100);
  var [trimDuration,setTrimDuration]=useState(0);
  var [trims,setTrims]=useState({}); // {vidId: {start,end,duration}}
  function toggleMute(vidId){
    setMutedVids(function(prev){var n=Object.assign({},prev);n[vidId]=!n[vidId];return n;});
  }

  var allEntries=[];
  Object.keys(videos).forEach(function(vin){
    (videos[vin]||[]).forEach(function(v){
      if(v.role===ALLPRO_ROLE&&!v.isDemo)allEntries.push(Object.assign({},v,{vin:vin}));
    });
  });
  allEntries.sort(function(a,b){return new Date(b.date||0)-new Date(a.date||0);});

  // Check for videos pending over 48hrs
  useEffect(function(){
    var overdue=allEntries.filter(function(v){
      var st=qcStatus[v.id]||"pending";
      if(st!=="pending")return false;
      var hrs=(Date.now()-new Date(v.date||0))/3600000;
      return hrs>PENDING_QC_HRS;
    });
    if(overdue.length>0)setPendingAlert(true);
  },[]);

  var stores=["All"].concat(allEntries.map(function(v){return v.dealerName;}).filter(function(v,i,a){return v&&a.indexOf(v)===i;}));

  // Stores with All-Pro upload activity, for the export filter
  var uploadAudit=getAudit().filter(function(e){return e.type==="video_upload";});
  var exportStoreIds=uploadAudit.map(function(e){return e.store;}).filter(function(v,i,a){return v&&a.indexOf(v)===i;});
  var exportStores=exportStoreIds.map(function(id){
    var d=SONIC_DEALERS.find(function(x){return x.id===id;});
    return {id:id,name:d?d.name:id};
  }).sort(function(a,b){return a.name.localeCompare(b.name);});

  function csvCell(v){
    var s=(v===undefined||v===null)?"":String(v);
    if(s.indexOf(",")>-1||s.indexOf("\"")>-1||s.indexOf("\n")>-1)return "\""+s.replace(/"/g,"\"\"")+"\"";
    return s;
  }
  function exportUploadCSV(){
    var startMs=new Date(expStart+"T00:00:00").getTime();
    var endMs=new Date(expEnd+"T23:59:59").getTime();
    var rows=uploadAudit.filter(function(e){
      var t=new Date(e.ts).getTime();
      if(t<startMs||t>endMs)return false;
      if(expStore!=="All"&&e.store!==expStore)return false;
      if(expAllProOnly&&e.role!==ALLPRO_ROLE)return false;
      return true;
    }).sort(function(a,b){return new Date(a.ts)-new Date(b.ts);});

    var header=["Date","Time","Photographer","Role","Store","Video Type","Vehicle","VIN","Duration (sec)"];
    var lines=[header.map(csvCell).join(",")];
    rows.forEach(function(e){
      var dt=new Date(e.ts);
      var dealer=SONIC_DEALERS.find(function(x){return x.id===e.store;});
      lines.push([
        dt.toLocaleDateString(),
        dt.toLocaleTimeString(),
        e.uploader||e.user||"",
        e.role||"",
        dealer?dealer.name:(e.store||""),
        e.videoType||"",
        e.vidName||"",
        e.vin||"",
        e.duration||0
      ].map(csvCell).join(","));
    });
    var csv=lines.join("\n");
    var blob=new Blob([csv],{type:"text/csv"});
    var url=URL.createObjectURL(blob);
    var a=document.createElement("a");
    a.href=url; a.download="allpro-uploads_"+expStart+"_to_"+expEnd+".csv"; a.click();
    URL.revokeObjectURL(url);
    return rows.length;
  }
  var filtered=allEntries.filter(function(v){
    var ms=storeF==="All"||v.dealerName===storeF;
    var st=qcStatus[v.id]||"pending";
    var mst=statusF==="All"||st===statusF;
    return ms&&mst;
  });

  function approve(vidId){
    setQcStatus(function(prev){var n=Object.assign({},prev);n[vidId]="approved";return n;});
  }
  function flagVideo(vidId){
    var reason=flagReason==="Custom reason..."?customReason.trim():flagReason;
    if(!reason)return;
    setFlags(function(prev){var n=Object.assign({},prev);n[vidId]={reason:reason,flaggedBy:user.name,flaggedAt:new Date().toISOString()};return n;});
    setQcStatus(function(prev){var n=Object.assign({},prev);n[vidId]="reshoot";return n;});
    setFlagging(null);setFlagReason("");setCustomReason("");
  }
  function removeFlag(vidId){
    setFlags(function(prev){var n=Object.assign({},prev);delete n[vidId];return n;});
    setQcStatus(function(prev){var n=Object.assign({},prev);n[vidId]="pending";return n;});
  }
  function saveNote(vidId){
    setQcNotes(function(prev){var n=Object.assign({},prev);n[vidId]=noteText;return n;});
    setNoteFor(null);setNoteText("");
  }

  var pendingCount=allEntries.filter(function(v){return (qcStatus[v.id]||"pending")==="pending";}).length;
  var approvedCount=allEntries.filter(function(v){return qcStatus[v.id]==="approved";}).length;
  var reshootCount=allEntries.filter(function(v){return qcStatus[v.id]==="reshoot";}).length;

  if(playVid){
    var st=qcStatus[playVid.id]||"pending";
    return <div style={rootStyle(th)}>
      <style>{getGS(th)}</style>
      <div style={{...hdr(th),display:"flex",alignItems:"center",gap:12}}>
        <button onClick={function(){setPlayVid(null);}} style={backBtn(th)}>←</button>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:13,fontWeight:600,color:th.text,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{playVid.name}</div>
          <div style={{fontSize:10,color:"#ff6b35"}}>{playVid.dealerName} · {playVid.uploader}</div>
        </div>
        <VTypeBadge type={playVid.videoType} small={true}/>
      </div>
      <video src={URL.createObjectURL(playVid.blob)} controls autoPlay playsInline muted={!!mutedVids[playVid.id]} style={{flex:1,width:"100%",background:"#000",objectFit:"contain"}}/>
      {trims[playVid.id]&&<div style={{padding:"4px 16px",background:"#4da6ff12",borderTop:"1px solid #4da6ff33",flexShrink:0}}>
        <div style={{fontSize:10,color:"#4da6ff",textAlign:"center"}}>✂️ Trimmed: {fmtTime(Math.round(trims[playVid.id].start))} – {fmtTime(Math.round(trims[playVid.id].end))} ({fmtTime(Math.round(trims[playVid.id].duration))})</div>
      </div>}
      {mutedVids[playVid.id]&&<div style={{padding:"4px 16px",background:"#ff6b3512",borderTop:"1px solid #ff6b3533",flexShrink:0}}>
        <div style={{fontSize:10,color:"#ff6b35",textAlign:"center"}}>🔇 Audio muted by QC</div>
      </div>}
      {/* Status banner */}
      <div style={{padding:"8px 16px",background:st==="approved"?"#00d97e18":st==="reshoot"?"#e8313a18":"#ffd70010",borderTop:"1px solid "+(st==="approved"?"#00d97e33":st==="reshoot"?"#e8313a33":"#ffd70033"),flexShrink:0}}>
        <div style={{fontSize:11,color:st==="approved"?"#00d97e":st==="reshoot"?"#e8313a":"#ffd700",fontWeight:700,textAlign:"center"}}>
          {st==="approved"?"✓ Approved":st==="reshoot"?"🚩 Flagged for reshoot - "+( flags[playVid.id]?flags[playVid.id].reason:""):"⏳ Pending review"}
        </div>
      </div>
      {/* QC note */}
      {noteFor===playVid.id?(
        <div style={{padding:"8px 16px",background:th.panel,borderTop:"1px solid "+th.border,flexShrink:0}}>
          <input style={{...inp(th),padding:"8px 12px",fontSize:13,marginBottom:6}} placeholder="Internal QC note (not visible to photographer)..." value={noteText} onChange={function(e){setNoteText(e.target.value);}} onKeyDown={function(e){if(e.key==="Enter")saveNote(playVid.id);}}/>
          <div style={{display:"flex",gap:8}}>
            <button onClick={function(){setNoteFor(null);}} style={{flex:1,padding:9,borderRadius:8,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:13,fontFamily:"'Barlow',sans-serif"}}>Cancel</button>
            <button onClick={function(){saveNote(playVid.id);}} style={{flex:1,padding:9,borderRadius:8,border:"none",background:"#4da6ff",color:"#fff",cursor:"pointer",fontSize:13,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>Save Note</button>
          </div>
        </div>
      ):(
        qcNotes[playVid.id]&&<div style={{padding:"8px 16px",background:th.panel,borderTop:"1px solid "+th.border,flexShrink:0}}>
          <div style={{fontSize:11,color:"#4da6ff",cursor:"pointer"}} onClick={function(){setNoteFor(playVid.id);setNoteText(qcNotes[playVid.id]||"");}}>📝 {qcNotes[playVid.id]}</div>
        </div>
      )}
      {editingVid&&<BottomSheet th={th} title="✂️ Trim Video" subtitle="Drag handles to set start and end points. QC-applied trims are saved as metadata for All-Pro to apply." onClose={function(){setEditingVid(null);}}>
        <video src={URL.createObjectURL(editingVid.blob)} controls playsInline
          onLoadedMetadata={function(e){setTrimDuration(e.target.duration||0);}}
          style={{width:"100%",borderRadius:8,background:"#000",maxHeight:180,objectFit:"contain",marginBottom:12}}/>
        <div style={{marginBottom:14}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
            <span style={{fontSize:11,color:th.muted}}>Start: {fmtTime(Math.round((trimStart/100)*trimDuration))}</span>
            <span style={{fontSize:11,color:th.muted}}>End: {fmtTime(Math.round((trimEnd/100)*trimDuration))}</span>
            <span style={{fontSize:11,color:"#00d97e",fontWeight:700}}>Duration: {fmtTime(Math.round(((trimEnd-trimStart)/100)*trimDuration))}</span>
          </div>
          <div style={{position:"relative",height:40}}>
            <div style={{position:"absolute",top:"50%",left:0,right:0,height:4,background:th.border,borderRadius:2,transform:"translateY(-50%)"}}/>
            <div style={{position:"absolute",top:"50%",left:trimStart+"%",right:(100-trimEnd)+"%",height:4,background:"#4da6ff",borderRadius:2,transform:"translateY(-50%)"}}/>
            <input type="range" min="0" max={trimEnd-1} value={trimStart} onChange={function(e){setTrimStart(Number(e.target.value));}}
              style={{position:"absolute",top:0,left:0,width:"100%",height:"100%",opacity:0,cursor:"pointer",zIndex:2}}/>
            <div style={{position:"absolute",top:"50%",left:trimStart+"%",width:20,height:20,borderRadius:"50%",background:"#4da6ff",border:"3px solid #fff",transform:"translate(-50%,-50%)",pointerEvents:"none",boxShadow:"0 2px 8px rgba(0,0,0,0.4)"}}/>
            <input type="range" min={trimStart+1} max="100" value={trimEnd} onChange={function(e){setTrimEnd(Number(e.target.value));}}
              style={{position:"absolute",top:0,left:0,width:"100%",height:"100%",opacity:0,cursor:"pointer",zIndex:3}}/>
            <div style={{position:"absolute",top:"50%",left:trimEnd+"%",width:20,height:20,borderRadius:"50%",background:"#4da6ff",border:"3px solid #fff",transform:"translate(-50%,-50%)",pointerEvents:"none",boxShadow:"0 2px 8px rgba(0,0,0,0.4)"}}/>
          </div>
        </div>
        {((trimEnd-trimStart)/100)*trimDuration<30&&<div style={{background:"#ffd70012",border:"1px solid #ffd70033",borderRadius:7,padding:"7px 10px",marginBottom:10,fontSize:11,color:"#ffd700"}}>⚠ Trimmed clip is under 30 seconds.</div>}
        <div style={{display:"flex",gap:10}}>
          <button onClick={function(){setEditingVid(null);}} style={{flex:1,padding:12,borderRadius:9,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:14,fontFamily:"'Barlow',sans-serif"}}>Cancel</button>
          <button onClick={function(){
            setTrims(function(prev){
              var n=Object.assign({},prev);
              n[editingVid.id]={startPct:trimStart,endPct:trimEnd,start:(trimStart/100)*trimDuration,end:(trimEnd/100)*trimDuration,duration:((trimEnd-trimStart)/100)*trimDuration};
              return n;
            });
            setEditingVid(null);
          }} style={{flex:1,padding:12,borderRadius:9,border:"none",background:"#4da6ff",color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>✂️ Save Trim</button>
        </div>
      </BottomSheet>}

      {/* Edit row: trim + mute (QC only) */}
      <div style={{padding:"10px 16px",background:th.panel,borderTop:"1px solid "+th.border,display:"flex",gap:10,flexShrink:0}}>
        <button onClick={function(){
          setEditingVid(playVid);
          var existing=trims[playVid.id];
          setTrimStart(existing?existing.startPct:0);
          setTrimEnd(existing?existing.endPct:100);
        }} style={{flex:1,padding:10,borderRadius:9,border:"1px solid #4da6ff44",background:"#4da6ff12",color:"#4da6ff",cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>✂️ Edit / Trim</button>
        <button onClick={function(){toggleMute(playVid.id);}} style={{flex:1,padding:10,borderRadius:9,border:"1px solid "+(mutedVids[playVid.id]?"#ff6b3544":th.border2),background:mutedVids[playVid.id]?"#ff6b3512":"transparent",color:mutedVids[playVid.id]?"#ff6b35":th.muted,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>{mutedVids[playVid.id]?"🔇 Muted":"🔊 Mute Audio"}</button>
      </div>
      <div style={{padding:"12px 16px 28px",background:th.panel,borderTop:"1px solid "+th.border,display:"flex",gap:10,flexShrink:0}}>
        {st!=="approved"&&<button onClick={function(){approve(playVid.id);}} style={{flex:1,padding:13,borderRadius:10,border:"none",background:"#00d97e",color:"#0a0c10",cursor:"pointer",fontSize:13,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>✓ Approve</button>}
        {st==="approved"&&<button onClick={function(){setQcStatus(function(prev){var n=Object.assign({},prev);n[playVid.id]="pending";return n;});}} style={{flex:1,padding:13,borderRadius:10,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:13,fontFamily:"'Barlow',sans-serif"}}>Remove Approval</button>}
        {st!=="reshoot"?<button onClick={function(){setFlagging(playVid.id);setPlayVid(null);}} style={{flex:1,padding:13,borderRadius:10,border:"1px solid #e8313a44",background:"#e8313a18",color:"#e8313a",cursor:"pointer",fontSize:13,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>🚩 Flag</button>
        :<button onClick={function(){removeFlag(playVid.id);}} style={{flex:1,padding:13,borderRadius:10,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:13,fontFamily:"'Barlow',sans-serif"}}>Remove Flag</button>}
        <button onClick={function(){setNoteFor(playVid.id);setNoteText(qcNotes[playVid.id]||"");}} style={{padding:"13px 14px",borderRadius:10,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:16}}>📝</button>
      </div>
    </div>;
  }

  return <div style={rootStyle(th)}>
    <style>{getGS(th)}</style>

    {/* Flag reason sheet */}
    {flagging&&<BottomSheet th={th} title="🚩 Flag for Reshoot" subtitle="Select a reason or write your own." onClose={function(){setFlagging(null);setFlagReason("");setCustomReason("");}}>
      {FLAG_REASONS.map(function(r){
        var active=flagReason===r;
        return <div key={r} onClick={function(){setFlagReason(r);}} style={{padding:"10px 12px",marginBottom:4,background:active?"#e8313a18":th.inp,border:"1px solid "+(active?"#e8313a55":th.border),borderRadius:8,cursor:"pointer",fontSize:13,color:active?"#e8313a":th.text}}>{active?"✓ ":""}{r}</div>;
      })}
      {flagReason==="Custom reason..."&&<textarea value={customReason} onChange={function(e){setCustomReason(e.target.value);}} placeholder="Describe what needs to be reshot..." style={{...inp(th),height:80,resize:"none",fontSize:13,marginTop:6,marginBottom:8}}/>}
      <div style={{display:"flex",gap:10,marginTop:8}}>
        <button onClick={function(){setFlagging(null);setFlagReason("");}} style={{flex:1,padding:12,borderRadius:9,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:14,fontFamily:"'Barlow',sans-serif"}}>Cancel</button>
        <button onClick={function(){flagVideo(flagging);}} disabled={!flagReason||(flagReason==="Custom reason..."&&!customReason.trim())} style={{flex:1,padding:12,borderRadius:9,border:"none",background:"#e8313a",color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700,fontFamily:"'Barlow',sans-serif",opacity:(!flagReason||(flagReason==="Custom reason..."&&!customReason.trim()))?0.5:1}}>Submit Flag</button>
      </div>
    </BottomSheet>}

    {noteFor&&!playVid&&<BottomSheet th={th} title="📝 QC Note" subtitle="Internal only — not visible to photographers." onClose={function(){setNoteFor(null);}}>
      <textarea value={noteText} onChange={function(e){setNoteText(e.target.value);}} placeholder="Add an internal note..." style={{...inp(th),height:100,resize:"none",fontSize:14,marginBottom:12}}/>
      <button onClick={function(){saveNote(noteFor);}} style={pbtn("#4da6ff")}>Save Note</button>
    </BottomSheet>}

    {/* Export upload log */}
    {showExport&&<BottomSheet th={th} title="📊 Export Upload Log" subtitle="Download a CSV of video uploads for any date range and store." onClose={function(){setShowExport(false);}}>
      <div style={{display:"flex",gap:8,marginBottom:6}}>
        {[
          ["Today",0,0],["Yesterday",1,1],["Last 7 days",6,0],["This month",new Date().getDate()-1,0]
        ].map(function(p2){
          return <button key={p2[0]} onClick={function(){
            var now=new Date();
            var start=new Date(now); start.setDate(start.getDate()-p2[1]);
            var end=new Date(now); end.setDate(end.getDate()-p2[2]);
            setExpStart(start.toISOString().slice(0,10));
            setExpEnd(end.toISOString().slice(0,10));
          }} style={{flex:1,padding:"6px 4px",borderRadius:7,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:10,fontFamily:"'Barlow',sans-serif"}}>{p2[0]}</button>;
        })}
      </div>
      <div style={{display:"flex",gap:8,marginBottom:10}}>
        <div style={{flex:1}}>
          <div style={{fontSize:10,color:th.faint,marginBottom:4,textTransform:"uppercase",letterSpacing:1}}>From</div>
          <input type="date" value={expStart} max={expEnd} onChange={function(e){setExpStart(e.target.value);}} style={{...inp(th),padding:"8px 10px",fontSize:13}}/>
        </div>
        <div style={{flex:1}}>
          <div style={{fontSize:10,color:th.faint,marginBottom:4,textTransform:"uppercase",letterSpacing:1}}>To</div>
          <input type="date" value={expEnd} min={expStart} max={new Date().toISOString().slice(0,10)} onChange={function(e){setExpEnd(e.target.value);}} style={{...inp(th),padding:"8px 10px",fontSize:13}}/>
        </div>
      </div>
      <div style={{marginBottom:10}}>
        <div style={{fontSize:10,color:th.faint,marginBottom:4,textTransform:"uppercase",letterSpacing:1}}>Store</div>
        <select value={expStore} onChange={function(e){setExpStore(e.target.value);}} style={{...inp(th),padding:"8px 10px",fontSize:13}}>
          <option value="All">All Stores</option>
          {exportStores.map(function(s){return <option key={s.id} value={s.id}>{s.name}</option>;})}
        </select>
      </div>
      <div onClick={function(){setExpAllProOnly(function(v){return !v;});}} style={{display:"flex",alignItems:"center",gap:10,marginBottom:14,cursor:"pointer"}}>
        <div style={{width:20,height:20,borderRadius:5,border:"2px solid "+(expAllProOnly?"#c084fc":th.border2),background:expAllProOnly?"#c084fc":"transparent",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
          {expAllProOnly&&<span style={{color:"#fff",fontSize:12,fontWeight:800}}>✓</span>}
        </div>
        <div style={{fontSize:12,color:th.text,fontWeight:600}}>All-Pro uploads only</div>
      </div>
      <button onClick={function(){
        var count=exportUploadCSV();
        p.onToast&&p.onToast(count>0?("Exported "+count+" upload"+(count===1?"":"s")+".") :"No uploads found for that range.");
      }} style={pbtn("#c084fc")}>⬇ Download CSV</button>
    </BottomSheet>}

    <div style={{...hdr(th)}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
        <button onClick={p.onClose} style={backBtn(th)}>←</button>
        <div style={{flex:1}}>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontWeight:800,fontSize:17,letterSpacing:2,color:th.text}}>QC REVIEW</div>
          <div style={{fontSize:9,color:"#c084fc",letterSpacing:1,textTransform:"uppercase"}}>All-Pro Quality Control · All Stores</div>
        </div>
        <div style={{textAlign:"right"}}>
          <div style={{fontSize:18,fontWeight:800,color:th.text,fontFamily:"'Barlow Condensed',sans-serif"}}>{allEntries.length}</div>
          <div style={{fontSize:9,color:th.muted}}>total</div>
        </div>
      </div>

      {pendingAlert&&<div style={{background:"#ffd70010",border:"1px solid #ffd70030",borderRadius:8,padding:"7px 12px",marginBottom:8,fontSize:11,color:"#ffd700",display:"flex",justifyContent:"space-between"}}>
        <span>⚠ Some videos have been pending review for over {PENDING_QC_HRS}hrs</span>
        <button onClick={function(){setPendingAlert(false);}} style={{background:"none",border:"none",color:"#ffd700",cursor:"pointer",fontSize:12}}>✕</button>
      </div>}

      {/* Store selector + export */}
      <div style={{display:"flex",gap:8,marginBottom:8}}>
        <button onClick={function(){setShowStores(true);}} style={{flex:1,padding:"9px 14px",background:th.inp,border:"1px solid "+(storeF==="All"?th.border:"#c084fc55"),borderRadius:9,color:storeF==="All"?th.muted:"#c084fc",cursor:"pointer",fontSize:12,fontFamily:"'Barlow',sans-serif",fontWeight:700,textAlign:"left",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <span>📍 {storeF==="All"?"All Stores":storeF}</span>
          <span>▾</span>
        </button>
        <button onClick={function(){setShowExport(true);}} style={{padding:"9px 14px",background:th.inp,border:"1px solid "+th.border,borderRadius:9,color:th.muted,cursor:"pointer",fontSize:12,fontFamily:"'Barlow',sans-serif",fontWeight:700,whiteSpace:"nowrap"}}>📊 Export</button>
      </div>

      {/* Status filter tabs */}
      <div style={{display:"flex",gap:5,marginBottom:8}}>
        {[["All","All",th.muted],["pending","⏳ "+pendingCount,"#ffd700"],["approved","✓ "+approvedCount,"#00d97e"],["reshoot","🚩 "+reshootCount,"#e8313a"]].map(function(item){
          var f=item[0]; var lbl2=item[1]; var c=item[2];
          return <button key={f} onClick={function(){setStatusF(f);}} style={{flex:1,padding:"6px 0",background:statusF===f?c+"18":"transparent",border:statusF===f?"1px solid "+c+"55":"1px solid "+th.border,borderRadius:7,color:statusF===f?c:th.muted,fontSize:10,cursor:"pointer",fontFamily:"'Barlow',sans-serif",fontWeight:700,whiteSpace:"nowrap"}}>{lbl2}</button>;
        })}
      </div>
    </div>

    {/* Store picker sheet */}
    {showStores&&<BottomSheet th={th} title="Select Store" subtitle="Browse inventory at any Sonic location" onClose={function(){setShowStores(false);}}>
      <div style={{maxHeight:300,overflowY:"auto"}}>
        {stores.map(function(s){
          return <div key={s} onClick={function(){setStoreF(s);setShowStores(false);}} style={{padding:"12px 4px",borderBottom:"1px solid "+th.border,cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontSize:13,color:s===storeF?"#c084fc":th.text,fontWeight:s===storeF?700:400}}>{s==="All"?"All Stores":s}</span>
            {s===storeF&&<span style={{color:"#c084fc",fontSize:12}}>✓</span>}
          </div>;
        })}
      </div>
    </BottomSheet>}

    <div style={{flex:1,overflowY:"auto",padding:12}}>
      <div style={{fontSize:10,color:th.faint,letterSpacing:1,textTransform:"uppercase",padding:"2px 2px 8px"}}>{filtered.length} videos</div>
      {filtered.length===0?(
        <div style={{textAlign:"center",padding:"60px 20px",color:th.faint}}>
          <div style={{fontSize:44,marginBottom:10}}>📋</div>
          <div>No videos in this view</div>
        </div>
      ):filtered.map(function(vid,i){
        var st=qcStatus[vid.id]||"pending";
        var isFlagged=st==="reshoot";
        var isApproved=st==="approved";
        var flagInfo=flags[vid.id];
        var hasNote=!!qcNotes[vid.id];
        var borderColor=isFlagged?"#e8313a44":isApproved?"#00d97e33":th.border;
        return <div key={vid.id+"-"+i} style={{background:th.card,border:"1px solid "+borderColor,borderRadius:12,overflow:"hidden",marginBottom:10}}>
          <div style={{position:"relative",paddingTop:"45%",background:"#141720",cursor:"pointer"}} onClick={function(){setPlayVid(vid);}}>
            <VideoThumb blob={vid.blob}/>
            <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",background:"rgba(0,0,0,0.2)"}}>
              <div style={{width:44,height:44,borderRadius:"50%",background:"rgba(232,49,58,0.88)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,color:"#fff",paddingLeft:3}}>▶</div>
            </div>
            <div style={{position:"absolute",top:8,left:8}}><VTypeBadge type={vid.videoType} small={true}/></div>
            <div style={{position:"absolute",top:8,right:8}}>
              {isFlagged&&<span style={{background:"#e8313a",color:"#fff",padding:"2px 7px",borderRadius:4,fontSize:9,fontWeight:800}}>🚩 RESHOOT</span>}
              {isApproved&&<span style={{background:"#00d97e",color:"#0a0c10",padding:"2px 7px",borderRadius:4,fontSize:9,fontWeight:800}}>✓ APPROVED</span>}
              {!isFlagged&&!isApproved&&<span style={{background:"#ffd70020",border:"1px solid #ffd70055",color:"#ffd700",padding:"2px 7px",borderRadius:4,fontSize:9,fontWeight:700}}>⏳ PENDING</span>}
            </div>
          </div>
          <div style={{padding:"10px 12px 12px"}}>
            <div style={{fontSize:13,fontWeight:600,color:th.text,marginBottom:4,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{vid.name}</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:4}}>
              <span style={{fontSize:10,color:"#ff6b35",background:"#ff6b3512",border:"1px solid #ff6b3533",padding:"1px 7px",borderRadius:3,fontWeight:700}}>📍 {vid.dealerName||"Unknown"}</span>
              <span style={{fontSize:10,color:"#c084fc",background:"#c084fc12",border:"1px solid #c084fc33",padding:"1px 7px",borderRadius:3,fontWeight:700}}>📷 {vid.uploader}</span>
              {hasNote&&<span style={{fontSize:10,color:"#4da6ff",background:"#4da6ff12",border:"1px solid #4da6ff33",padding:"1px 7px",borderRadius:3,fontWeight:700}}>📝 Note</span>}
            </div>
            <div style={{fontSize:10,color:th.faint,marginBottom:isFlagged?6:8}}>{fmtDate(vid.date)}</div>
            {isFlagged&&flagInfo&&<div style={{background:"#e8313a12",border:"1px solid #e8313a33",borderRadius:7,padding:"7px 10px",marginBottom:8}}>
              <div style={{fontSize:11,color:"#e8313a",fontWeight:700,marginBottom:1}}>🚩 {flagInfo.reason}</div>
              <div style={{fontSize:9,color:th.muted}}>by {flagInfo.flaggedBy} · {fmtDaysAgo(flagInfo.flaggedAt)}</div>
            </div>}
            <div style={{display:"flex",gap:7}}>
              <button onClick={function(){setPlayVid(vid);}} style={{flex:1,padding:"9px 0",background:"#e8313a18",border:"1px solid #e8313a44",color:"#e8313a",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>▶ Review</button>
              {!isApproved&&<button onClick={function(){approve(vid.id);}} style={{flex:1,padding:"9px 0",background:"#00d97e18",border:"1px solid #00d97e44",color:"#00d97e",borderRadius:8,cursor:"pointer",fontSize:12,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>✓ Approve</button>}
              {isApproved&&<button onClick={function(){setQcStatus(function(prev){var n=Object.assign({},prev);n[vid.id]="pending";return n;});}} style={{flex:1,padding:"9px 0",background:th.inp,border:"1px solid "+th.border2,color:th.muted,borderRadius:8,cursor:"pointer",fontSize:11,fontFamily:"'Barlow',sans-serif"}}>Remove ✓</button>}
              {!isFlagged?<button onClick={function(){setFlagging(vid.id);}} style={{padding:"9px 12px",background:th.inp,border:"1px solid "+th.border2,color:th.muted,borderRadius:8,cursor:"pointer",fontSize:12}}>🚩</button>
              :<button onClick={function(){removeFlag(vid.id);}} style={{padding:"9px 12px",background:th.inp,border:"1px solid "+th.border2,color:th.faint,borderRadius:8,cursor:"pointer",fontSize:11}}>✕</button>}
            </div>
          </div>
        </div>;
      })}
    </div>
  </div>;
}

// ─── Manager Dashboard ─────────────────────────────────────────────────────────
function ManagerDash(p) {
  var th=p.th; var videos=p.videos; var sentLog=p.sentLog; var inventory=p.inventory;
  var [tab,setTab]=useState("activity");
  var [unlocked,setUnlocked]=useState(false);
  var [unlockedAt,setUnlockedAt]=useState(null);
  var [showPK,setShowPK]=useState(false);
  // Auto-expire manager unlock after 5 minutes (SEC-03)
  useEffect(function(){
    if(!unlocked||!unlockedAt)return;
    var iv=setInterval(function(){
      if(Date.now()-unlockedAt>5*60*1000){setUnlocked(false);setUnlockedAt(null);}
    },15000);
    return function(){clearInterval(iv);};
  },[unlocked,unlockedAt]);
  var [pkInput,setPKInput]=useState("");
  var [pkErr,setPKErr]=useState("");
  var [grossPerDeal,setGross]=useState("3000");
  var [showGoals,setShowGoals]=useState(false);
  var [goals,setGoals]=useState({});
  var [staffNotes,setStaffNotes]=useState({});
  var [editNote,setEditNote]=useState(null);
  var [noteText,setNoteText]=useState("");
  var [selectedPerson,setSelectedPerson]=useState(null);
  var [compareMode,setCompareMode]=useState(false);

  var MANAGER_PK=getStoreSettings(p.dealerId||"").managerPk||"1234";
  function tryUnlock(){
    if(pkInput===MANAGER_PK){setUnlocked(true);setUnlockedAt(Date.now());setShowPK(false);setPKErr("");setPKInput("");}
    else{setPKErr("Incorrect passkey.");setPKInput("");}
  }

  var allSends=[];
  Object.keys(sentLog).forEach(function(vin){
    (sentLog[vin]||[]).forEach(function(s){allSends.push(Object.assign({},s,{vin:vin}));});
  });

  var byPerson={};
  allSends.forEach(function(s){
    if(!s.sentBy)return;
    if(!byPerson[s.sentBy])byPerson[s.sentBy]={name:s.sentBy,sends:0,customers:[],outcomes:{Sold:0,Visited:0,Responded:0}};
    byPerson[s.sentBy].sends++;
    if(s.custName&&byPerson[s.sentBy].customers.indexOf(s.custName)===-1)byPerson[s.sentBy].customers.push(s.custName);
    if(s.outcome&&byPerson[s.sentBy].outcomes[s.outcome]!==undefined)byPerson[s.sentBy].outcomes[s.outcome]++;
  });
  var people=Object.values(byPerson).sort(function(a,b){return b.sends-a.sends;});

  var totalVehicles=inventory.length;
  var withOfficial=inventory.filter(function(v){return (videos[v.vin]||[]).some(function(x){return x.videoType==="Official"&&!x.isDemo;});}).length;
  var withAny=inventory.filter(function(v){return (videos[v.vin]||[]).filter(function(x){return !x.isDemo;}).length>0;}).length;
  var totalVideos=Object.values(videos).flat().filter(function(v){return !v.isDemo;}).length;
  var totalSends=allSends.length;
  var totalSold=allSends.filter(function(s){return s.outcome==="Sold";}).length;
  var pct1=totalVehicles>0?Math.round(withOfficial/totalVehicles*100):0;
  var pct2=totalVehicles>0?Math.round(withAny/totalVehicles*100):0;
  var estRevenue=totalSold*Number(grossPerDeal||0);

  var inactive=people.filter(function(person){
    var lastSend=allSends.filter(function(s){return s.sentBy===person.name;}).sort(function(a,b){return new Date(b.sentAt)-new Date(a.sentAt);});
    if(lastSend.length===0)return true;
    var daysSince=(Date.now()-new Date(lastSend[0].sentAt))/86400000;
    return daysSince>INACTIVITY_DAYS;
  });

  var missing=inventory.filter(function(v){return !(videos[v.vin]||[]).some(function(x){return x.videoType==="Official"&&!x.isDemo;});});

  var cards=[
    {val:totalVideos,label:"Videos Recorded",clr:"#00d97e"},
    {val:totalSends,label:"Videos Sent",clr:"#4da6ff"},
    {val:people.length,label:"Active Senders",clr:"#ffd700"},
    {val:withOfficial,label:"w/ Official",clr:"#ff6b35"},
    {val:totalSold,label:"Deals (est.)",clr:"#c084fc"},
    {val:"$"+estRevenue.toLocaleString(),label:"Est. Revenue",clr:"#00d97e"},
  ];

  // Individual person deep dive
  if(selectedPerson){
    var pp=selectedPerson;
    var personSends=allSends.filter(function(s){return s.sentBy===pp.name;}).sort(function(a,b){return new Date(b.sentAt)-new Date(a.sentAt);});
    var goal=goals[pp.name]||0;
    var goalPct=goal>0?Math.min(100,Math.round(pp.sends/goal*100)):0;
    return <div style={rootStyle(th)}>
      <style>{getGS(th)}</style>
      <div style={{...hdr(th),display:"flex",alignItems:"center",gap:10}}>
        <button onClick={function(){setSelectedPerson(null);}} style={backBtn(th)}>←</button>
        <div style={{flex:1}}>
          <div style={{fontSize:16,fontWeight:800,color:th.text}}>{pp.name}</div>
          <div style={{fontSize:10,color:th.muted}}>{pp.sends} sends · {pp.customers.length} unique customers</div>
        </div>
      </div>
      <div style={{flex:1,overflowY:"auto",padding:14}}>
        {goal>0&&<div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
            <span style={{fontSize:12,fontWeight:700,color:th.text}}>Weekly Goal: {pp.sends}/{goal} sends</span>
            <span style={{fontSize:12,color:"#00d97e",fontWeight:700}}>{goalPct}%</span>
          </div>
          <div style={{height:8,background:th.border,borderRadius:4,overflow:"hidden"}}>
            <div style={{height:"100%",width:goalPct+"%",background:"#00d97e",borderRadius:4}}/>
          </div>
        </div>}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
          {[["Sold",pp.outcomes&&pp.outcomes.Sold||0,"#00d97e"],["Visited",pp.outcomes&&pp.outcomes.Visited||0,"#ffd700"],["Responded",pp.outcomes&&pp.outcomes.Responded||0,"#4da6ff"],["No Reply",pp.sends-(pp.outcomes&&(pp.outcomes.Sold+pp.outcomes.Visited+pp.outcomes.Responded)||0),"#555"]].map(function(item){
            return <div key={item[0]} style={{...card(th),padding:"10px 12px"}}>
              <div style={{fontSize:20,fontWeight:800,color:item[2],fontFamily:"'Barlow Condensed',sans-serif"}}>{item[1]}</div>
              <div style={{fontSize:9,color:th.muted,textTransform:"uppercase",letterSpacing:1}}>{item[0]}</div>
            </div>;
          })}
        </div>
        {staffNotes[pp.name]&&<div style={{background:"#4da6ff12",border:"1px solid #4da6ff33",borderRadius:9,padding:"10px 14px",marginBottom:12,fontSize:12,color:"#4da6ff"}}>📋 Manager note: {staffNotes[pp.name]}</div>}
        <div style={{fontSize:10,color:th.faint,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Recent sends</div>
        {personSends.slice(0,20).map(function(s,i){
          var oc=OUTCOME_COLORS[s.outcome||"No Response"]||th.muted;
          var veh=inventory.find(function(v){return v.vin===s.vin;});
          return <div key={i} style={{...card(th),padding:"10px 12px",marginBottom:6}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
              <div style={{fontSize:12,fontWeight:600,color:th.text}}>{s.custName}</div>
              <OutcomeBadge outcome={s.outcome||"No Response"}/>
            </div>
            {veh&&<div style={{fontSize:10,color:th.muted}}>🚗 {veh.year} {veh.make} {veh.model}</div>}
            <div style={{fontSize:9,color:th.faint,marginTop:2}}>{fmtDaysAgo(s.sentAt)}</div>
          </div>;
        })}
      </div>
    </div>;
  }

  return <div style={rootStyle(th)}>
    <style>{getGS(th)}</style>
    {showPK&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.88)",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:24,fontFamily:"'Barlow',sans-serif"}}>
      <div style={{background:th.panel,border:"1px solid "+th.border,borderRadius:14,padding:"24px 20px",maxWidth:300,width:"100%"}}>
        <div style={{fontSize:16,fontWeight:700,color:th.text,marginBottom:4,textAlign:"center"}}>🔐 Manager Access</div>
        <div style={{fontSize:12,color:th.muted,textAlign:"center",marginBottom:16}}>Enter passkey to view full details.</div>
        <input type="password" inputMode="numeric" maxLength={6} placeholder="Passkey" value={pkInput} onChange={function(e){setPKInput(e.target.value);setPKErr("");}} onKeyDown={function(e){if(e.key==="Enter")tryUnlock();}} style={{...inp(th),fontSize:20,letterSpacing:6,textAlign:"center",marginBottom:8}}/>
        {pkErr&&<ErrBox msg={pkErr}/>}
        <div style={{display:"flex",gap:10}}>
          <button onClick={function(){setShowPK(false);setPKInput("");}} style={{flex:1,padding:12,borderRadius:9,border:"1px solid "+th.border2,background:"transparent",color:th.muted,cursor:"pointer",fontSize:14,fontFamily:"'Barlow',sans-serif"}}>Cancel</button>
          <button onClick={tryUnlock} style={{flex:1,padding:12,borderRadius:9,border:"none",background:"#e8313a",color:"#fff",cursor:"pointer",fontSize:14,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>Unlock</button>
        </div>
      </div>
    </div>}

    <div style={{...hdr(th)}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
        <button onClick={p.onClose} style={backBtn(th)}>←</button>
        <div style={{flex:1}}>
          <div style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:17,fontWeight:800,color:th.text,letterSpacing:2}}>MANAGER DASHBOARD</div>
          <div style={{fontSize:9,color:"#e8313a",letterSpacing:1,textTransform:"uppercase"}}>{p.dealerName}</div>
        </div>
        {inactive.length>0&&<div style={{background:"#ffd70018",border:"1px solid #ffd70033",borderRadius:7,padding:"4px 10px",fontSize:10,color:"#ffd700",fontWeight:700}}>⚠ {inactive.length} inactive</div>}
      </div>
      <div style={{display:"flex",gap:5}}>
        {[["activity","📊"],["feed","📋"],["coverage","📹"],["settings","⚙️"]].map(function(item){
          var id=item[0]; var icon=item[1];
          return <button key={id} onClick={function(){setTab(id);}} style={{flex:1,padding:"8px 0",background:tab===id?"#e8313a1a":"transparent",border:tab===id?"1px solid #e8313a55":"1px solid "+th.border,borderRadius:8,color:tab===id?"#e8313a":th.muted,fontSize:16,cursor:"pointer"}}>{icon}</button>;
        })}
      </div>
    </div>

    <div style={{flex:1,overflowY:"auto",padding:14}}>

      {/* Activity tab */}
      {tab==="activity"&&<div>
        {/* ROI calculator */}
        <div style={{...card(th),padding:"12px 14px",marginBottom:12}}>
          <div style={{fontSize:10,color:th.muted,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>ROI Calculator</div>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{flex:1}}>
              <div style={{fontSize:11,color:th.sub,marginBottom:4}}>Avg. gross per deal</div>
              <input style={{...inp(th),padding:"8px 10px",fontSize:14}} value={grossPerDeal} onChange={function(e){setGross(e.target.value.replace(/\D/g,""));}} placeholder="3000"/>
            </div>
            <div style={{flex:1,textAlign:"center"}}>
              <div style={{fontSize:22,fontWeight:800,color:"#00d97e",fontFamily:"'Barlow Condensed',sans-serif"}}>${estRevenue.toLocaleString()}</div>
              <div style={{fontSize:9,color:th.muted}}>est. revenue from {totalSold} sold</div>
            </div>
          </div>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
          {cards.map(function(c2){
            return <div key={c2.label} style={{...card(th),padding:"12px 14px"}}>
              <div style={{fontSize:22,fontWeight:800,color:c2.clr,fontFamily:"'Barlow Condensed',sans-serif"}}>{c2.val}</div>
              <div style={{fontSize:9,color:th.muted,textTransform:"uppercase",letterSpacing:1,marginTop:2}}>{c2.label}</div>
            </div>;
          })}
        </div>

        {inactive.length>0&&<div style={{background:"#ffd70010",border:"1px solid #ffd70030",borderRadius:9,padding:"10px 14px",marginBottom:12}}>
          <div style={{fontSize:12,color:"#ffd700",fontWeight:700,marginBottom:6}}>⚠ Inactive Staff ({inactive.length})</div>
          {inactive.map(function(person){
            return <div key={person.name} style={{fontSize:11,color:th.muted,padding:"2px 0"}}>{person.name} — no sends in {INACTIVITY_DAYS}+ days</div>;
          })}
        </div>}

        <div style={{fontSize:10,color:th.faint,letterSpacing:1,textTransform:"uppercase",marginBottom:10}}>Leaderboard</div>
        {people.length===0?(
          <div style={{textAlign:"center",padding:"40px 20px",color:th.faint}}>
            <div style={{fontSize:36,marginBottom:8}}>📤</div>
            <div>No activity yet</div>
          </div>
        ):people.map(function(pp,i){
          var goal=goals[pp.name]||0;
          var hasNote=!!staffNotes[pp.name];
          return <div key={pp.name} onClick={function(){setSelectedPerson(pp);}} style={{...card(th),padding:"11px 14px",marginBottom:8,display:"flex",alignItems:"center",gap:12,cursor:"pointer"}}>
            <div style={{width:32,height:32,borderRadius:"50%",background:"#e8313a18",border:"1px solid #e8313a33",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,fontWeight:800,color:"#e8313a",flexShrink:0}}>{i+1}</div>
            <div style={{flex:1}}>
              <div style={{display:"flex",alignItems:"center",gap:6}}>
                <div style={{fontSize:13,fontWeight:700,color:th.text}}>{pp.name}</div>
                {hasNote&&<span style={{fontSize:9,color:"#4da6ff"}}>📋</span>}
              </div>
              <div style={{fontSize:11,color:th.muted}}>{pp.customers.length} customers{goal>0?" · goal: "+pp.sends+"/"+goal:""}</div>
              {goal>0&&<div style={{height:3,background:th.border,borderRadius:2,marginTop:4,overflow:"hidden"}}>
                <div style={{height:"100%",width:Math.min(100,Math.round(pp.sends/goal*100))+"%",background:"#00d97e",borderRadius:2}}/>
              </div>}
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:18,fontWeight:800,color:"#4da6ff",fontFamily:"'Barlow Condensed',sans-serif"}}>{pp.sends}</div>
              <div style={{fontSize:9,color:th.faint}}>sends</div>
            </div>
          </div>;
        })}
        {/* Video Analytics — Most Sent Videos */}
        <div style={{...card(th),padding:"12px 14px",marginBottom:12}}>
          <div style={{fontSize:10,color:th.muted,letterSpacing:1,textTransform:"uppercase",marginBottom:10}}>📊 Most Sent Videos</div>
          {(function(){
            var byVehicle={};
            allSends.forEach(function(s){
              var veh=inventory.find(function(v){return v.vin===s.vin;});
              var label=veh?(veh.year+" "+veh.make+" "+veh.model):(s.vehicleName||"Unknown vehicle");
              var key=s.vin+"|"+(s.videoType||"Walk-around");
              if(!byVehicle[key])byVehicle[key]={label:label,stock:veh?veh.stock:"",videoType:s.videoType||"Walk-around",count:0,sold:0};
              byVehicle[key].count++;
              if(s.outcome==="Sold")byVehicle[key].sold++;
            });
            var ranked=Object.values(byVehicle).sort(function(a,b){return b.count-a.count;}).slice(0,5);
            if(ranked.length===0)return <div style={{fontSize:11,color:th.faint,textAlign:"center",padding:"8px 0"}}>No sends yet this period.</div>;
            return ranked.map(function(r,i){
              var vc=VT_COLORS[r.videoType]||"#888";
              return <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"7px 0",borderBottom:i<ranked.length-1?"1px solid "+th.border:"none"}}>
                <div style={{width:22,height:22,borderRadius:"50%",background:"#4da6ff18",border:"1px solid #4da6ff33",display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:800,color:"#4da6ff",flexShrink:0}}>{i+1}</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:12,color:th.text,fontWeight:600,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{r.label}</div>
                  <div style={{display:"flex",gap:6,marginTop:2}}>
                    <VTypeBadge type={r.videoType} small={true}/>
                    {r.stock&&<span style={{fontSize:9,color:th.faint}}>#{r.stock}</span>}
                    {r.sold>0&&<span style={{fontSize:9,color:"#00d97e",fontWeight:700}}>💰 {r.sold} sold</span>}
                  </div>
                </div>
                <div style={{textAlign:"right",flexShrink:0}}>
                  <div style={{fontSize:18,fontWeight:800,color:"#00d97e",fontFamily:"'Barlow Condensed',sans-serif"}}>{r.count}</div>
                  <div style={{fontSize:9,color:th.faint}}>sends</div>
                </div>
              </div>;
            });
          })()}
        </div>


      </div>}

      {/* Staff Activity tab */}
      {tab==="staff"&&<div>
        <div style={{fontSize:14,fontWeight:700,color:th.text,marginBottom:4}}>Staff Activity</div>
        <div style={{fontSize:11,color:th.muted,marginBottom:12}}>Login history, video activity, and send activity for everyone at {p.dealerName}.</div>
        {(function(){
          var dealerUsers=Object.values(getUsers()).filter(function(u){return u.dealerId===p.dealerId;});
          var audit=getAudit();
          if(dealerUsers.length===0)return <div style={{textAlign:"center",padding:"30px 0",color:th.faint,fontSize:12}}>No staff accounts yet</div>;
          return dealerUsers.map(function(u){
            var myAudit=audit.filter(function(e){return e.user===u.email;});
            var logins=myAudit.filter(function(e){return e.type==="login";});
            var uploads=myAudit.filter(function(e){return e.type==="video_upload";});
            var sends=myAudit.filter(function(e){return e.type==="video_sent";});
            var lastLogin=logins.length?logins[0].ts:null;
            var lastActive=myAudit.length?myAudit[0].ts:null;
            var rc=ROLE_COLORS[u.role]||"#888";
            var isOnline=lastActive&&(Date.now()-new Date(lastActive))<10*60*1000;
            return <div key={u.email} style={{...card(th),borderRadius:10,padding:"11px 14px",marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:6}}>
                <div>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{fontSize:13,fontWeight:700,color:th.text}}>{u.displayName||u.name}</div>
                    {isOnline&&<span style={{width:7,height:7,borderRadius:"50%",background:"#00d97e",display:"inline-block"}}/>}
                  </div>
                  <div style={{fontSize:9,color:rc,fontWeight:700,background:rc+"18",border:"1px solid "+rc+"33",padding:"1px 6px",borderRadius:3,display:"inline-block",marginTop:3}}>{u.role}</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontSize:10,color:th.muted}}>Last active</div>
                  <div style={{fontSize:11,color:isOnline?"#00d97e":th.text,fontWeight:600}}>{lastActive?(isOnline?"Online now":fmtDaysAgo(lastActive)):"Never"}</div>
                </div>
              </div>
              <div style={{display:"flex",gap:8}}>
                <div style={{flex:1,background:th.inp,border:"1px solid "+th.border,borderRadius:7,padding:"6px 8px",textAlign:"center"}}>
                  <div style={{fontSize:14,fontWeight:800,color:"#4da6ff",fontFamily:"'Barlow Condensed',sans-serif"}}>{logins.length}</div>
                  <div style={{fontSize:8,color:th.muted,textTransform:"uppercase"}}>Logins</div>
                </div>
                <div style={{flex:1,background:th.inp,border:"1px solid "+th.border,borderRadius:7,padding:"6px 8px",textAlign:"center"}}>
                  <div style={{fontSize:14,fontWeight:800,color:"#ff6b35",fontFamily:"'Barlow Condensed',sans-serif"}}>{uploads.length}</div>
                  <div style={{fontSize:8,color:th.muted,textTransform:"uppercase"}}>Uploads</div>
                </div>
                <div style={{flex:1,background:th.inp,border:"1px solid "+th.border,borderRadius:7,padding:"6px 8px",textAlign:"center"}}>
                  <div style={{fontSize:14,fontWeight:800,color:"#00d97e",fontFamily:"'Barlow Condensed',sans-serif"}}>{sends.length}</div>
                  <div style={{fontSize:8,color:th.muted,textTransform:"uppercase"}}>Sends</div>
                </div>
              </div>
              <div style={{fontSize:9,color:th.faint,marginTop:6}}>First login: {lastLogin?fmtDate(u.createdAt||lastLogin):"—"} · Account created {fmtDate(u.createdAt||new Date())}</div>
            </div>;
          });
        })()}
      </div>}

      {/* All sends feed */}
      {tab==="feed"&&<div>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
          <div style={{fontSize:10,color:th.faint,letterSpacing:1,textTransform:"uppercase"}}>{allSends.length} total sends</div>
          {!unlocked?<button onClick={function(){setShowPK(true);}} style={{background:"#e8313a18",border:"1px solid #e8313a44",color:"#e8313a",padding:"5px 12px",borderRadius:7,cursor:"pointer",fontSize:11,fontWeight:700,fontFamily:"'Barlow',sans-serif"}}>🔐 Unlock</button>
          :<span style={{fontSize:10,color:"#00d97e",fontWeight:700}}>🔓 Full Access</span>}
        </div>
        {allSends.length===0?(
          <div style={{textAlign:"center",padding:"40px 20px",color:th.faint}}>
            <div style={{fontSize:36,marginBottom:8}}>📤</div>
            <div>No sends recorded yet</div>
          </div>
        ):allSends.slice().sort(function(a,b){return new Date(b.sentAt||0)-new Date(a.sentAt||0);}).map(function(e,i){
          var veh=inventory.find(function(v){return v.vin===e.vin;});
          return <div key={i} style={{...card(th),padding:"11px 14px",marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
              <div>
                <div style={{fontSize:13,fontWeight:700,color:th.text}}>{e.custName}</div>
                <div style={{fontSize:10,color:th.muted,marginTop:2}}>
                  Sent by <span style={{color:"#4da6ff",fontWeight:600}}>{e.sentBy}</span> · {fmtDaysAgo(e.sentAt)}
                </div>
              </div>
              <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:4}}>
                <VTypeBadge type={e.videoType||"Walk-around"} small={true}/>
                <OutcomeBadge outcome={e.outcome||"No Response"}/>
              </div>
            </div>
            {veh&&<div style={{fontSize:11,color:th.muted,marginBottom:unlocked?6:0}}>🚗 {veh.year} {veh.make} {veh.model} · <span style={{fontFamily:"monospace"}}>#{veh.stock}</span></div>}
            {unlocked&&<div style={{borderTop:"1px solid "+th.border,paddingTop:8,marginTop:6}}>
              {e.custContact&&<div style={{fontSize:11,color:th.muted,marginBottom:4}}>📞 {e.custContact}</div>}
              <div style={{fontSize:11,color:th.muted,fontStyle:"italic",lineHeight:1.4}}>"{(e.msg||"").slice(0,140)}{(e.msg||"").length>140?"...":""}"</div>
            </div>}
            {!unlocked&&<div style={{borderTop:"1px solid "+th.border,paddingTop:6,marginTop:6}}>
              <div style={{fontSize:10,color:th.faint,fontStyle:"italic"}}>🔐 Unlock to view message and contact</div>
            </div>}
          </div>;
        })}
      </div>}

      {/* Coverage tab */}
      {tab==="coverage"&&<div>
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
            <span style={{fontSize:12,fontWeight:700,color:th.text}}>Official video coverage</span>
            <span style={{fontSize:12,color:"#00d97e",fontWeight:700}}>{pct1}%</span>
          </div>
          <div style={{height:8,background:th.border,borderRadius:4,overflow:"hidden"}}>
            <div style={{height:"100%",width:pct1+"%",background:"#00d97e",borderRadius:4}}/>
          </div>
          <div style={{fontSize:10,color:th.muted,marginTop:6}}>{withOfficial} of {totalVehicles} vehicles</div>
        </div>
        <div style={{...card(th),padding:14,marginBottom:14}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
            <span style={{fontSize:12,fontWeight:700,color:th.text}}>Any video coverage</span>
            <span style={{fontSize:12,color:"#4da6ff",fontWeight:700}}>{pct2}%</span>
          </div>
          <div style={{height:8,background:th.border,borderRadius:4,overflow:"hidden"}}>
            <div style={{height:"100%",width:pct2+"%",background:"#4da6ff",borderRadius:4}}/>
          </div>
          <div style={{fontSize:10,color:th.muted,marginTop:6}}>{withAny} of {totalVehicles} vehicles</div>
        </div>
        <div style={{fontSize:10,color:th.faint,letterSpacing:1,textTransform:"uppercase",marginBottom:10}}>Missing official ({missing.length})</div>
        {missing.map(function(v){
          return <div key={v.vin} style={{...card(th),padding:"10px 12px",marginBottom:6,display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:8,height:8,borderRadius:"50%",background:"#e8313a",flexShrink:0}}/>
            <div style={{flex:1}}>
              <div style={{fontSize:12,fontWeight:600,color:th.text}}>{v.year} {v.make} {v.model}</div>
              <div style={{fontSize:10,color:th.muted}}>#{v.stock} · {v.type}</div>
            </div>
            <DaysBadge days={v.daysOnLot||0}/>
          </div>;
        })}
      </div>}

      {/* Settings tab */}
      {tab==="settings"&&<div>
        <div style={{fontSize:14,fontWeight:700,color:th.text,marginBottom:12}}>Store Settings</div>

        {/* Manager passkey */}
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:th.text,marginBottom:4}}>🔐 Manager Passkey</div>
          <div style={{fontSize:11,color:th.muted,marginBottom:10}}>Current: {getStoreSettings(p.dealerId||"").managerPk||"1234"}</div>
          <input style={{...inp(th),fontSize:18,letterSpacing:4}} placeholder="New passkey" type="password" inputMode="numeric" maxLength={6} id="new-pk"/>
          <button onClick={function(){
            var val=document.getElementById("new-pk").value;
            if(val.length>=4){saveStoreSettings(p.dealerId||"",Object.assign({},getStoreSettings(p.dealerId||""),{managerPk:val}));p.onToast("Passkey updated!");}
          }} style={{...pbtn("#e8313a"),marginTop:8,padding:10,fontSize:13}}>Update Passkey</button>
        </div>

        {/* Blackout hours */}
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:th.text,marginBottom:4}}>⏰ Send Blackout Hours</div>
          <div style={{fontSize:11,color:th.muted,marginBottom:10}}>Block sends outside business hours</div>
          <div style={{display:"flex",gap:10}}>
            <div style={{flex:1}}>
              <span style={lbl(th)}>Stop at</span>
              <select style={inp(th)} onChange={function(e){saveStoreSettings(p.dealerId||"",Object.assign({},getStoreSettings(p.dealerId||""),{blackoutStart:Number(e.target.value)}));}}>
                {[17,18,19,20,21,22,23].map(function(h){return <option key={h} value={h}>{h}:00</option>;})}
              </select>
            </div>
            <div style={{flex:1}}>
              <span style={lbl(th)}>Resume at</span>
              <select style={inp(th)} onChange={function(e){saveStoreSettings(p.dealerId||"",Object.assign({},getStoreSettings(p.dealerId||""),{blackoutEnd:Number(e.target.value)}));}}>
                {[6,7,8,9,10].map(function(h){return <option key={h} value={h}>{h}:00</option>;})}
              </select>
            </div>
          </div>
        </div>

        {/* Staff Certification Status */}
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:th.text,marginBottom:10}}>📚 Staff Certification</div>
          {people.length===0&&<div style={{fontSize:11,color:th.faint}}>No staff yet</div>}
          {people.map(function(pp){
            var cert=(_db.certifications&&_db.certifications[pp.name])||{};
            var mods=["terms","camera","sending","outcomes","billing"];
            var done=mods.filter(function(m){return !!cert[m];}).length;
            var pct=Math.round(done/mods.length*100);
            return <div key={pp.name} style={{marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:3}}>
                <span style={{fontSize:12,color:th.text}}>{pp.name}</span>
                <span style={{fontSize:10,color:pct===100?"#00d97e":"#ffd700",fontWeight:700}}>{pct}%{pct===100?" 🎓":""}</span>
              </div>
              <div style={{height:4,background:th.border,borderRadius:2,overflow:"hidden"}}>
                <div style={{height:"100%",width:pct+"%",background:pct===100?"#00d97e":"#ffd700",borderRadius:2}}/>
              </div>
            </div>;
          })}
        </div>
                {/* Goals */}
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:th.text,marginBottom:10}}>🎯 Weekly Send Goals</div>
          {people.map(function(pp){
            return <div key={pp.name} style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
              <div style={{flex:1,fontSize:12,color:th.text}}>{pp.name}</div>
              <input type="number" style={{...inp(th),width:70,padding:"6px 10px",fontSize:13,textAlign:"center"}} value={goals[pp.name]||""} placeholder="0" onChange={function(e){setGoals(function(prev){var n=Object.assign({},prev);n[pp.name]=Number(e.target.value);return n;});}}/>
            </div>;
          })}
        </div>

        {/* Staff notes */}
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:th.text,marginBottom:10}}>📋 Staff Notes (internal only)</div>
          {people.map(function(pp){
            return <div key={pp.name} style={{marginBottom:10}}>
              <div style={{fontSize:11,color:th.muted,marginBottom:4}}>{pp.name}</div>
              <input style={{...inp(th),padding:"8px 10px",fontSize:12}} placeholder="Manager note..." value={staffNotes[pp.name]||""} onChange={function(e){setStaffNotes(function(prev){var n=Object.assign({},prev);n[pp.name]=e.target.value;return n;});}}/>
            </div>;
          })}
        </div>

        {/* QR code */}
        <div style={{...card(th),padding:14,marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:th.text,marginBottom:4}}>📱 Staff Signup QR Code</div>
          <div style={{fontSize:11,color:th.muted,marginBottom:8}}>Print and post in the break room. Staff scan to sign up with this store pre-selected.</div>
          <QRPlaceholder th={th} storeName={p.dealerName}/>
        </div>

        {/* Store deactivation */}
        <div style={{...card(th),padding:14,marginBottom:12,border:"1px solid #e8313a44"}}>
          <div style={{fontSize:12,fontWeight:700,color:"#e8313a",marginBottom:4}}>⚠ Store Controls</div>
          <div style={{fontSize:11,color:th.muted,marginBottom:10}}>Admin use only. Contact Video Vault support to deactivate this store.</div>
          <button onClick={function(){p.onToast("Contact Video Vault admin to deactivate this store.","warn");}} style={{...pbtn("transparent"),border:"1px solid #e8313a55",color:"#e8313a",padding:10,fontSize:12}}>Request Store Deactivation</button>
        </div>
      </div>}
    </div>
  </div>;
}


